// The EFA goal depends on the agent's track. A student can't write business yet,
// so the win is booking the field appointment for their colleague to run. A licensed
// agent runs it themselves, so the win is getting the client on the books.
const efaGoal = (agentType) => agentType === "licensed" ? "Get Client on the Books" : "Book Field Appointment";

