// Generates ONE short, natural coaching hint based on the actual conversation so far.
const buildHintPrompt = (mode, situation, contextType, agentType, linkType, messages, lang) => {
  const transcript = messages.map(m => m.role === "system" ? `[${m.content}]` : `${m.role === "user" ? "AGENT (the person training)" : situation.personaName.toUpperCase()}: ${m.content}`).join("\n");
  const quiet = messages.length > 0 && messages[messages.length-1].role === "system";
  const isRecruit = linkType === "recruit_unlicensed" || linkType === "recruit_licensed";
  const agentTurns = messages.filter(m => m.role === "user").length;
  if (mode === "qualify") {
    const lt = LINK_TYPES[linkType];
    return `You are a sales coach watching a live conversation. The AGENT is practicing how to QUALIFY a prospect (find out if they are a real prospect) through natural conversation. They are NOT pitching or sending a link yet.

PROSPECT: ${situation.personaName}, ${situation.personaAge}, ${situation.personaTrait}. How they talk: ${situation.personaStyle}
SIGNALS THAT MATTER: ${lt.qualifySignals.slice(0,5).join("; ")}

CONVERSATION SO FAR:
${transcript}

Give the agent ONE short hint for their very next message, based on what the prospect actually just said. Tell them the specific next question or move. If the prospect dropped a signal, point to it and give a natural follow-up question they could ask. Keep it conversational, never pitch yet.

Rules: Plain, simple words a 10th grader reads easily. One or two short sentences. Match the prospect's tone and energy, mirror how THEY talk (formal or casual, hyped or chill). If you suggest words to say, make them sound like a real person talking out loud (casual, no dashes).${LANG_COACH[lang] || ""} Do not greet, do not explain, just the hint.`;
  }
  const at = AGENT_TYPES[agentType];
  const script = (contextType === "warm") ? at.scriptWarm : (contextType === "social") ? (at.scriptSocial || at.scriptCold) : at.scriptCold;
  const lastProspectMsg = [...messages].reverse().find(m => m.role === "assistant");
  const lp = (lastProspectMsg?.content || "").toLowerCase();
  const askedWhatIsIt = /what(?:'?s| is| ?s)?\s+(?:it|this|that)\b/i.test(lp) || /what(?:'?s| is)?\s+this\s+(?:for|about)/i.test(lp) || /what do you need.*feedback/i.test(lp) || /what am i looking at/i.test(lp) || /what.?s? it for/i.test(lp);
  const linkAlreadySent = messages.some(m => m.role === "user" && /https?:\/\/|mavericksagency\.org|here'?s the link|sent it over|sending it over/i.test(m.content));
  return `You are a sales coach watching a live text conversation. The AGENT (${at.label}) is practicing how to naturally bridge a normal chat into sending a FAST link, following this flow:
1) warm up naturally
2) bridge with permission: "${script.opener}"
3) if yes: "${script.ifYes}"
4) send the link asking for feedback

They must NOT explain what the link is, mention insurance/products/comp/licensing, or write long messages. The link does the explaining.

PROSPECT: ${situation.personaName}, ${situation.personaAge}, ${situation.personaTrait}. How they talk: ${situation.personaStyle}${situation.history ? ` History between you: ${situation.history}` : ""}
${situation.inbound ? `
INBOUND SITUATION: the PROSPECT started this conversation, not the agent.${situation.inboundType === "flip" ? ` The prospect actually messaged the agent trying to recruit THEM. The agent's whole move is to FLIP it: do not get recruited, do not argue, get genuinely curious about how things are really going for the prospect. The person doing the pitching is usually the one quietly struggling. Coach the agent to turn it around with a real question about the prospect's own situation, surface their pain, and only then bridge. There is no cold opener here.` : ` The prospect reached out warm and curious about what the agent does. Do NOT coach a cold opener or a permission ask, that's already past. Coach the agent to reply like a peer, turn the curiosity back on the prospect, get them talking about their own situation, find the pain, then bridge off it.`}` : ""}

CONVERSATION SO FAR:
${transcript}

Give the agent ONE short hint for their very next message, based on what the prospect ACTUALLY just said.

${askedWhatIsIt ? `THEY JUST ASKED WHAT IT IS. This is the moment that makes or breaks it, and the rule is the agent does NOT explain. No naming insurance, money, products, the company, or the category, and no paragraph. Coach a short, human, curiosity keeping answer:
- If earlier in THIS conversation the prospect mentioned something real (a new baby, a raise, bills, hating their job, wanting out, building something), tie the answer to THAT in their own words, for example: "honestly after what you said about [their thing] i just figured you'd want to see it, take a peek and tell me what you think". Referencing why you thought of them is exactly how a real person answers, and it stays honest because they actually said it.
- If nothing real has come up yet, keep it light and human with no pretext: "ha it's easier to just show you than explain over text, take a quick look and lmk what stands out, no pressure".
Never coach a fake "i randomly came across this" line. Short, warm, no explaining, then hand it back to them. Give the actual words to text.` : quiet ? (linkAlreadySent ? `The prospect has gone quiet AFTER the agent already sent the link. This is a real follow-up. Coach a short, light nudge, curiosity not pressure, never guilt or a hard push. Something a real person texts after a gap. Show the actual words.` : `The conversation went quiet during warm-up and NO link or ask was ever made, so this is NOT a follow-up and there is no cadence to run. Coach a warm, human re-open, lighter than where they left off, no ask and no agenda. The strongest move is to circle back to something the prospect actually shared earlier (their kid, their weekend, whatever they opened up about) to show the agent was listening, especially if the agent's last message talked over them. Do NOT use "no rush on my end" or anything implying a pending ask, because there isn't one. A few hours of silence is not rejection, patience is fine. Give the actual words to text.`) : `If the agent has ALREADY sent the link: their job is done, they are a messenger and delivery is the finish line. Do NOT tell them to explain more, sell, or fish for a reaction. Coach the clean close: thank them, keep it easy, and add a soft referral like "if you know anyone who'd find this valuable, feel free to pass it along." The move is to close, not expand. Show the actual words.
${isRecruit ? `THIS IS A RECRUIT. The agent is not pretending to be neutral, they are in this, and the prospect can smell a fake. So the bridge has to be HONEST and grounded in something the prospect actually said.
- A recruit bridge always grows from a REAL pain the prospect revealed. Never bridge on nothing. NEVER coach "I came across something and thought of you" or any version of stumbling onto a random link, the agent is an active agent, that line is dishonest and hollow.
- If the prospect has NOT revealed a pain yet (an active builder, a stranger, someone keeping it surface), the move is to KEEP DISCOVERING, not to bridge. Coach a real question: how's business actually going, how do they like being independent or at their shop, what's the hardest part right now. Surface a genuine pain first.
- Once they HAVE named something real, bridge by naming it back: "since you said [their exact pain], I actually think you'd get something out of this, can I send it to you?" That is honest and it ties to their words.
- NEVER commiserate into sameness ("yeah same here"). Never brag. Never explain. If they turn out genuinely happy with no pain, do not force it or manufacture one, keep it real and leave the door open.
` : ``}PACING COMES FIRST. Do not rush the bridge. ${agentTurns <= 2 ? `It is still early (the agent has barely warmed up). The move right now is almost certainly NOT to bridge. ` : ``}One or two exchanges is almost never enough, especially warm market. If the prospect just gave a short or surface reply, tell the agent to warm up more: ask a real follow-up about what they just said, get them talking, let it breathe. Bridging after a line or two sounds scripted and burns a warm connection. Only bridge once there's genuine back and forth AND a natural opening.

When it IS finally time to bridge: ${isRecruit ? `tie it to the exact pain they revealed: "since you mentioned [their words], I actually think you'd find this valuable. can I send it to you?" Honest, grounded in what they said, no stumbled-across fiction, no commiserating. If they haven't revealed a real pain yet, do NOT bridge, give them the next discovery question instead.` : `remember the agent is NOT pitching, they're asking a small favor (an honest take), and the bridge should feel like a smooth continuation of THIS chat, not a pivot bolted on. Read the whole conversation, especially how it opened and the thread they shared (a new baby, a busy season, a raise, a move, whatever it was), and grow the ask out of that. The smooth shape, woven into one natural message: (1) warmly react to what they just said ("aw that's great", "love that", "so happy for you"); (2) if it's a warm chat with someone they know, a light check-in beat that ties back to why they reached out fits here ("I really just wanted to check in, glad you're doing well"), in a cold or social chat skip that and just ride the rapport; (3) respect their time out loud, named to THEIR actual situation ("I know you're a busy mom, I won't hold you up", "while I've got you for a sec"); (4) then the small ask ("can I run something by you real quick?"). Give the actual words as one flowing text, built from what they said, not the bare script line on its own.`} Do NOT hand them the bare script line by itself. Lowercase ok, no dashes, one or two sentences.
If the prospect just said yes or showed interest: tell them to send the link now, keep the framing short.
If the prospect raised an objection: give the short, calm way to handle it without over-explaining.
If they still need to warm up (this is most early replies): give them the specific next thing to react to or ask. Do not bridge yet. The prospect will often NOT ask the agent back or carry the small talk, they may give a short flat reply and just leave it there. That dead air is the agent's to fill, not a dead end or a sign to wait. When the prospect gives a flat reply with no question back, do NOT tell the agent to wait or match the flatness, coach them to carry it: react to something specific, ask the prospect a real question about their life or what they shared, bring the energy themselves. Driving the warm-up when the other person isn't is the actual skill here.${agentType === "student" && isRecruit ? `
THIS AGENT IS A STUDENT recruiting someone, and ${linkType === "recruit_licensed" ? `someone more experienced than them` : `a peer`}. The fear is real: they feel like they have no business reaching out, like they'll get exposed for not knowing enough. If the prospect tests them (how long have you been doing this, are you licensed, what do you know about the comp), do NOT let the student shrink ("I'm just a student", "I'm still learning") and do NOT let them fake expertise. Coach the connector frame: they own being newer in one calm line with zero apology, and they point at the link and the colleague who'll walk through the details. They are the person who found something and made the intro, not the expert. Give them the actual confident, no-apology words.` : ``}`}

Rules: Plain, simple words a 10th grader reads easily. One or two short sentences. Match the prospect's tone and energy, mirror how THEY text (formal or casual, hyped or chill). Any words to text must sound like a real person (casual, lowercase ok, NO dashes). Never coach a self-disqualifying hedge ("not sure if this is relevant", "this probably isn't for you", "you might not be interested but"): it kills curiosity and reads as no conviction. Lower the pressure, not the interest. Owning that it's random ("ok this is random but") is fine, pre-judging the offer is not.${LANG_COACH[lang] || ""} Do not greet, do not explain yourself, just the hint.`;
};

// ─── BRIDGE BUILDER (instant fallback) ───
// Teaches a SMOOTH transition: the pivot should feel caused by what they just
// said, woven in with connective tissue, not a reaction and a script bolted together.
const buildBridge = (messages) => {
  const them = messages.filter(m => m.role === "assistant").map(m => m.content.toLowerCase()).join(" ");
  let line = null;
  if (/baby|newborn|kid|son|daughter|pregnan|diaper|sleep/i.test(them))
    line = "Ride what they shared into it: \"haha sounds like the little one's running the show right now. anyway I know you've got your hands full so I won't hold you up, real quick while I got you, can I run something by you?\"";
  else if (/house|home|move|mortgage|closing/i.test(them))
    line = "Build off their news: \"congrats again, that's a huge step. hey real quick while it's on my mind, can I run something by you?\"";
  else if (/married|wedding|honeymoon|wife|husband|fianc/i.test(them))
    line = "Use their energy: \"haha still in the newlywed glow, love that. funny enough that's kinda why I hit you up, can I run something by you real quick?\"";
  else if (/job|work|boss|shift|overtime|grind|burnt out|burnout/i.test(them))
    line = "Let the pivot grow from it: \"man that grind wears on you for real. actually that kinda ties into why I reached out, can I run something by you real quick?\"";
  else if (/money|bills|broke|paycheck|expensive|tight|afford|debt/i.test(them))
    line = "Connect it to your reason: \"for real, everything's so expensive right now. that actually ties into something I wanted to ask you, can I run it by you quick?\"";
  else if (/tired|stressed|overwhelmed|a lot right now|exhausted/i.test(them))
    line = "Meet them where they are, then ease in: \"sounds like you've got a lot on your plate honestly. real quick though while I got you, can I run something by you?\"";
  else if (/promo|raise|new job|started.*(job|role|position)/i.test(them))
    line = "Match the win: \"that's awesome, things are clearly moving for you. hey funny timing actually, can I run something by you real quick?\"";
  else if (/crypto|side hustle|business|invest|hustle/i.test(them))
    line = "Use their drive: \"you're always building something, I respect it. real quick, that actually reminds me, can I run something by you?\"";
  if (line) return "Remember you're not pitching, you're asking a small favor. Let it grow out of what they just shared, react first, respect their time out loud so the ask feels tiny. " + line;
  return "You're not pitching, you're asking a small favor. React to what they just said, then keep it tiny: \"[quick real reaction]... I really just wanted to check in. hey I don't wanna hold you up, but real quick while I got you, can I run something by you?\"";
};

// ─── OPENER IDEAS (tailored to the actual person) ───
// Generates 3 warm-up openers specific to THIS persona and situation, not a
// generic per-market list. These are the natural way to START the chat, never
// the script opener or a pitch.
const buildOpenerPrompt = (situation, contextType, mode, lang) => {
  const where = mode === "qualify" ? "a natural discovery conversation (no pitch, no link)" : `a ${contextType} market conversation`;
  const startVerb = mode === "qualify" ? "say to start" : "text to start";
  const speakNoun = mode === "qualify" ? "talking" : "texting";
  return `Give 3 natural opening messages an agent could ${startVerb} ${where} with this exact person. These are warm-up openers only. They are NOT a pitch, NOT a link, and NOT the "can I run something by you" line. They have no agenda yet.

PERSON: ${situation.personaName}, ${situation.personaAge}. ${situation.personaTrait}. ${situation.personaStyle}
SITUATION: ${situation.setup}
HOW THE CHAT STARTS: ${situation.openingContext}

Each opener must fit THIS person and what is actually going on with them. Reference their real situation, not a generic hello. Sound like a real person ${speakNoun}: warm, casual, specific, short. No dashes. No selling.

POSITIONING, IMPORTANT: relate and get them talking, but NEVER commiserate into sameness. Do NOT agree that you're in the same hole ("same here", "feels like it keeps getting worse", "I'm struggling too", "it's wild out there"). That puts you on the same sinking boat and kills any reason for them to hear you out later. Instead acknowledge what they're feeling and open the vent (how long has that been weighing on you, what's been the hardest part, what would change things for you), staying calm and steady like someone who has a handle on things, not drowning with them. Don't brag or pitch either. You are the person who relates AND quietly has a way forward, so draw them out, never join the misery.${LANG_REPLY[lang] || ""}

Respond ONLY with valid JSON, no backticks:
[{"text":"the opener message","vibe":"2 to 4 word label for the angle"},{"text":"...","vibe":"..."},{"text":"...","vibe":"..."}]`;
};

// ─── HINT GENERATOR ───
const getHint = (messages, exchangeCount, mode, situation, agentType, contextType) => {
  const last = messages.length > 0 ? messages[messages.length - 1] : null;
  const lc = last?.content?.toLowerCase() || "";
  const at = agentType ? AGENT_TYPES[agentType] : null;
  const script = at ? ((contextType === "warm") ? at.scriptWarm : (contextType === "social") ? (at.scriptSocial || at.scriptCold) : at.scriptCold) : null;
  if (messages.length === 0) {
    if (mode === "qualify") return "Start with normal conversation. Ask about their life. Signals come from genuine questions.";
    if (situation?.warmupHint) return situation.warmupHint;
    return "What would you naturally say to this person if you WEREN'T trying to send a link?";
  }
  if (last?.role === "assistant") {
    // QUALIFY MODE: discovery only. Never suggest the link script here.
    if (mode === "qualify") {
      if (/kid|baby|son|daughter|pregnant|family|married|wife|husband|spouse/i.test(lc)) return "Family came up. Dig in: 'How's that been for you guys?'";
      if (/job|work|boss|career|hours|schedule|fired|laid off|quit/i.test(lc)) return "Work signal. Ask: 'Is that something you want to change?'";
      if (/money|bills|broke|paycheck|afford|debt|expensive|save|income/i.test(lc)) return "Money signal. Ask: 'What would feel different if that wasn't a worry?'";
      if (/hate|stressed|frustrated|tired|sick of|over it|stuck|a lot right now|overwhelmed/i.test(lc)) return "They're opening up. Don't pitch. Just ask one more real question about it.";
      if (/what do you do|what are you up to|how about you|you still/i.test(lc)) return "They asked about you. Keep it short, then turn it back to them.";
      return "They're talking. Go one layer deeper on what they just said. Don't pitch yet.";
    }
    // SIM MODE: link-send coaching.
    const linkSent = messages.some(m => m.role === "user" && looksLikeLink(m.content));
    if (linkSent) {
      return "You already sent it, your job's done. Close it clean: 'awesome, thanks for taking a look. and hey, if you know anyone who'd wanna learn a bit about their money, feel free to send them the link too.' Don't explain more or wait around.";
    }
    // INBOUND: prospect contacted first. Coach the flip / warm reply, not a cold open.
    const agentTurns = messages.filter(m => m.role === "user").length;
    if (situation?.inbound && agentTurns === 0) {
      return situation.warmupHint || (situation.inboundType === "flip"
        ? "They came to recruit YOU. Don't get recruited, flip it. Get curious about how it's really going for them."
        : "They reached out to you, that's warm. Don't pitch back, turn it around and get them talking about their own situation.");
    }
    if (/what (is it|do you do|exactly)|tell me more|explain/i.test(lc)) {
      if (script?.ifWhatIsIt) return `They asked what it is. Script: "${script.ifWhatIsIt}"`;
      return "They're baiting you to explain. Don't. Redirect: 'Honestly easier to just show you.'";
    }
    if (/mlm|pyramid|scam|scheme|one of those/i.test(lc)) return "Don't defend. Laugh it off: 'Haha no nothing like that.'";
    if (/don.?t have time|too busy|swamped/i.test(lc)) return "Don't push. 'Takes 2 min, look whenever.'";
    if (/how much|cost|price|pay|fee/i.test(lc)) return "It's free. 'Doesn't cost anything, just want your feedback.'";
    if (/ask my (wife|husband|spouse)|check with/i.test(lc)) return "Great sign. 'For sure! I'll send it so you both can look.'";
    if (lc.length < 15 && /^(k|ok|cool|sure|idk|hmm|maybe|i guess)/.test(lc.trim())) return "They're fading. Send the link NOW.";
    if (/sounds (good|cool|interesting)|send (it|me)|sure|I.?m (down|interested|curious)|yeah/i.test(lc)) {
      if (script) return `They said yes! Script: "${script.ifYes}"`;
      return "They're open, send the link NOW.";
    }
    if (exchangeCount >= 3) return buildBridge(messages);
  }
  return null;
};

