// Phone frame — defined at module level so it stays stable across re-renders
// (defining it inside the component would remount the whole tree on every keystroke
//  and the text input would lose focus after each character)
function PhoneShell({ children, noScroll, cl, theme }) {
  const ico = cl.text;
  return (
    <div style={{ display:"flex", justifyContent:"center", alignItems:"center", minHeight:"100vh", background:cl.pageBg, padding:"12px 0", fontFamily:SF }}>
      <style>{`::-webkit-scrollbar{width:0;height:0;display:none}*{scrollbar-width:none;-ms-overflow-style:none}`}</style>
      <div style={{
        width: 393, maxWidth:"100vw", height:"min(852px, 100vh - 24px)",
        background: cl.phoneBg, borderRadius: 44, position:"relative",
        display:"flex", flexDirection:"column", overflow:"hidden",
        boxShadow: cl.shellShadow, color: cl.text,
      }}>
        <div style={{ position:"absolute", top:10, left:"50%", transform:"translateX(-50%)", width:126, height:36, background:"#000", borderRadius:20, zIndex:50 }} />
        <div style={{ height:56, flexShrink:0, display:"flex", alignItems:"flex-end", justifyContent:"space-between", padding:"0 32px 4px", fontSize:14, fontWeight:600, color:cl.text, zIndex:40 }}>
          <span style={{fontSize:15,fontWeight:700,letterSpacing:-0.3}}>9:41</span>
          <div style={{display:"flex",gap:5,alignItems:"center"}}>
            <svg width="18" height="12" viewBox="0 0 18 12"><path d="M1 4.2C3.7 1.4 7.3 0 11 0s7.3 1.4 10 4.2" fill="none" stroke={ico} strokeWidth="1.5" transform="translate(-2,2) scale(0.9)"/><path d="M4 7.2C5.8 5.2 8.3 4 11 4s5.2 1.2 7 3.2" fill="none" stroke={ico} strokeWidth="1.5" transform="translate(-2,2) scale(0.9)"/><circle cx="9" cy="10" r="1.5" fill={ico}/></svg>
            <svg width="16" height="11" viewBox="0 0 16 11"><rect x="0" y="0" width="3" height="11" rx="1" fill={ico} opacity="0.3"/><rect x="0" y="6" width="3" height="5" rx="1" fill={ico}/><rect x="4.5" y="0" width="3" height="11" rx="1" fill={ico} opacity="0.3"/><rect x="4.5" y="4" width="3" height="7" rx="1" fill={ico}/><rect x="9" y="0" width="3" height="11" rx="1" fill={ico} opacity="0.3"/><rect x="9" y="2" width="3" height="9" rx="1" fill={ico}/><rect x="13.5" y="0" width="3" height="11" rx="1" fill={ico}/></svg>
            <svg width="27" height="13" viewBox="0 0 27 13"><rect x="0" y="0.5" width="23" height="12" rx="3.5" stroke={ico} strokeWidth="1" fill="none" opacity="0.35"/><rect x="1.5" y="2" width="16" height="9" rx="2" fill={cl.green}/><rect x="24" y="4" width="2.5" height="5" rx="1" fill={ico} opacity="0.4"/></svg>
          </div>
        </div>
        <div style={{ flex:1, display:"flex", flexDirection:"column", overflow: noScroll ? "hidden" : "auto", position:"relative", color: cl.text }}>
          {children}
        </div>
        <div style={{ height:26, flexShrink:0, display:"flex", alignItems:"center", justifyContent:"center" }}>
          <div style={{ width:134, height:5, borderRadius:3, background: cl.indicator }} />
        </div>
      </div>
    </div>
  );
}

function BackBtn({ onClick, label, cl }) {
  return (
    <button onClick={onClick} style={{ background:"none", border:"none", color:cl.accent, fontSize:17, cursor:"pointer", fontFamily:SF, padding:"0", display:"flex", alignItems:"center", gap:4 }}>
      <svg width="10" height="17" viewBox="0 0 10 17" fill="none"><path d="M9 1L1.5 8.5L9 16" stroke={cl.accent} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
      {label || "Back"}
    </button>
  );
}

// ═══ COMPONENT ═══
export default function FASTLinkSim() {
  const [screen, setScreen] = useState("home");
  const [mode, setMode] = useState(null);
  const [agentType, setAgentType] = useState(null);
  const [agentName, setAgentName] = useState("");
  const [welcomeName, setWelcomeName] = useState("");
  const [welcomeTrack, setWelcomeTrack] = useState("student");
  const [linkType, setLinkType] = useState(null);
  const [contextType, setContextType] = useState(null);
  const [situation, setSituation] = useState(null);
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [scoring, setScoring] = useState(null);
  const [scoringLoading, setScoringLoading] = useState(false);
  const [exchangeCount, setExchangeCount] = useState(0);
  const [simComplete, setSimComplete] = useState(false);
  const [linkSent, setLinkSent] = useState(false);
  const [closing, setClosing] = useState(false);
  const [warnings, setWarnings] = useState([]);
  const [stats, setStats] = useState({ played:0, passed:0, total:0 });
  const [customInput, setCustomInput] = useState("");
  const [customLoading, setCustomLoading] = useState(false);
  const [dragWarned, setDragWarned] = useState(false);
  const [hint, setHint] = useState(null);
  const [hintLoading, setHintLoading] = useState(false);
  const [hintDismissed, setHintDismissed] = useState(false);
  const [hintsUsed, setHintsUsed] = useState(0);
  const [quietPending, setQuietPending] = useState(false);
  const [quietCount, setQuietCount] = useState(0);
  const [pendingFollowUp, setPendingFollowUp] = useState(false);
  const [autoCloseArmed, setAutoCloseArmed] = useState(false);
  const [openersOpen, setOpenersOpen] = useState(false);
  const [openerIdeas, setOpenerIdeas] = useState(null);
  const [openerLoading, setOpenerLoading] = useState(false);
  const [openerUsed, setOpenerUsed] = useState(false);
  const [showCheat, setShowCheat] = useState(false);
  const hintTimer = useRef(null);
  const hintGenKey = useRef(null);
  const endRef = useRef(null);
  const inputRef = useRef(null);
  const [spotterIndex, setSpotterIndex] = useState(0);
  const [spotterAnswer, setSpotterAnswer] = useState(null);
  const [spotterRevealed, setSpotterRevealed] = useState(false);
  const [spotterStats, setSpotterStats] = useState({ correct:0, total:0 });
  const [spotterOrder, setSpotterOrder] = useState([]);
  const [theme, setTheme] = useState("mavericks");
  const [pbTrack, setPbTrack] = useState("student");
  const [pbPath, setPbPath] = useState("efa");
  const [scriptVariant, setScriptVariant] = useState({});
  const [settingsOpen, setSettingsOpen] = useState(false);
  const [lang, setLang] = useState("en");
  const [difficulty, setDifficulty] = useState("medium");
  const [openSections, setOpenSections] = useState({ breakdown:false });
  const [mavMessages, setMavMessages] = useState([]);
  const [mavContext, setMavContext] = useState("");
  const [mavTrack, setMavTrack] = useState(null);
  const [mavGreeting, setMavGreeting] = useState("");
  const [mavInput, setMavInput] = useState("");
  const [mavLoading, setMavLoading] = useState(false);
  const [regenLoading, setRegenLoading] = useState(false);
  const mavEndRef = useRef(null);

  const MAX = mode === "qualify" ? 8 : 10;

  useEffect(() => { endRef.current?.scrollIntoView({ behavior:"smooth" }); }, [messages, loading]);
  useEffect(() => { mavEndRef.current?.scrollIntoView({ behavior:"smooth" }); }, [mavMessages, mavLoading]);
  // Keep the Playbook opening on the agent's chosen track. Identity is not stored,
  // so a fresh session always starts at the Welcome screen and re-asks the name.
  useEffect(() => { if (agentType) setPbTrack(agentType); }, [agentType]);

  useEffect(() => {
    if (mode === "sim" && (contextType === "cold" || contextType === "social") && exchangeCount >= 8 && !dragWarned && !simComplete) {
      setWarnings(p => [...p, { text:"Good rapport going. Start looking for your opening to bridge before they fade.", turn:exchangeCount }]);
      setDragWarned(true);
    }
  }, [exchangeCount]);

  useEffect(() => {
    // Hints are on-demand now (Ask Mav AI lifeline). Just clear any shown hint
    // when the round ends or the screen changes.
    if (screen !== "sim" || simComplete) { setHint(null); setHintLoading(false); }
  }, [screen, simComplete]);


  // Opener ideas: tailored to the persona, one generation per conversation.
  // First tap generates and reveals. After that it only toggles the same set.
  const genOpeners = async () => {
    if (openerUsed) { setOpenersOpen(o => !o); return; }
    setOpenerUsed(true); setOpenersOpen(true); setOpenerLoading(true);
    try {
      const r = await fetch(API_URL, { method:"POST", headers:{"Content-Type":"application/json"}, body:JSON.stringify({ model:"claude-sonnet-4-6", max_tokens:500, messages:[{role:"user",content:buildOpenerPrompt(situation, contextType, mode, lang)}] }) });
      const d = await r.json();
      const arr = JSON.parse((d.content?.[0]?.text || "").replace(/```json|```/g,"").trim());
      setOpenerIdeas(Array.isArray(arr) ? arr.slice(0,3) : null);
    } catch(e) {
      // Fallback to the generic per-market list if generation fails
      const ctx = mode === "qualify" ? "qualify" : (contextType || "warm");
      setOpenerIdeas((OPENERS[ctx] || OPENERS.warm).examples);
      console.error(e);
    }
    setOpenerLoading(false);
  };

  // Build a valid API message list from our messages, dropping silence notes
  // and merging any consecutive same-role turns so the roles still alternate.
  const toApiMessages = (msgs) => {
    const out = [];
    for (const m of msgs) {
      if (m.role === "system") continue;
      const role = m.role === "user" ? "user" : "assistant";
      if (out.length && out[out.length-1].role === role) out[out.length-1].content += "\n" + m.content;
      else out.push({ role, content: m.content });
    }
    // The API must start with a user turn. Inbound scenarios seed the prospect's
    // (assistant) opener first, so drop any leading assistant turns here; the
    // opener is carried in the system prompt instead.
    while (out.length && out[0].role === "assistant") out.shift();
    return out;
  };

  // Varied "they went quiet" status lines. Plain, no dashes.
  const SILENCE_NOTES = [
    (n)=>`5 hours later. ${n} still hasn't replied.`,
    (n)=>`Next morning. Nothing back from ${n} yet.`,
    (n)=>`A few hours have gone by with no response from ${n}.`,
    (n)=>`Two days later, still no word from ${n}.`,
    (n)=>`A full day passed and ${n} went quiet.`,
    (n)=>`${n} hasn't gotten back to you since yesterday.`,
  ];
  // Returns a quiet event: either a "Seen" left-on-read receipt (the brutal one)
  // or a time-gap note. content is what the model/coach sees, display is the UI.
  const pickQuietEvent = (n) => {
    if (Math.random() < 0.45) {
      return { role:"system", kind:"seen", content:`${n} read your message and left you on read. No reply.`, display:"Seen" };
    }
    const note = SILENCE_NOTES[Math.floor(Math.random()*SILENCE_NOTES.length)](n);
    return { role:"system", kind:"gap", content:note, display:note };
  };

  // Decide if the prospect goes quiet instead of replying. Sim only (qualifier
  // is in person). Most likely right after a link is sent, since that's the real
  // follow-up moment. Capped so it never gets frustrating.
  const shouldGoQuiet = (agentText) => {
    if (mode !== "sim" || quietCount >= 2 || exchangeCount < 2) return false;
    const sentLink = /https?:\/\/|mavericksagency\.org|here'?s the link/i.test(agentText);
    let p = sentLink ? 0.6 : (contextType === "cold" || contextType === "social") ? 0.22 : 0.1;
    return Math.random() < p;
  };

  // Ask Mav AI lifeline: deliberate, capped at 2 per conversation.
  const askMav = async () => {
    if (hintsUsed >= 2 || hintLoading || simComplete || loading) return;
    setHintsUsed(n => n + 1);
    setHint(null);
    setHintLoading(true);
    if (messages.length === 0 && lang === "en") {
      const h = getHint(messages, exchangeCount, mode, situation, agentType, contextType);
      setHint(h || "Just start like a normal person. React to what's going on with them, no agenda yet.");
      setHintLoading(false);
      return;
    }
    try {
      const r = await fetch(API_URL, { method:"POST", headers:{"Content-Type":"application/json"}, body:JSON.stringify({ model:"claude-sonnet-4-6", max_tokens:300, messages:[{role:"user",content:buildHintPrompt(mode, situation, contextType, agentType, linkType, messages, lang)}] }) });
      const d = await r.json();
      const h = (d.content?.[0]?.text || "").trim() || getHint(messages, exchangeCount, mode, situation, agentType, contextType);
      setHint(h || "Keep it short. React to their last message, then take one real step toward the link.");
    } catch(e) {
      setHint(getHint(messages, exchangeCount, mode, situation, agentType, contextType) || "Keep it short. React to what they said, then bridge naturally.");
      console.error(e);
    }
    setHintLoading(false);
  };

  const pick = (s, ctx) => {
    setSituation(s); setContextType(ctx); setMessages(s.inbound && s.firstMessage ? [{ role:"assistant", content:s.firstMessage }] : []); setExchangeCount(0);
    setSimComplete(false); setLinkSent(false); setClosing(false); setAutoCloseArmed(false); setScoring(null); setWarnings([]); setDragWarned(false); setDifficulty(rollDifficulty());
    setHint(null); setHintDismissed(false); setHintsUsed(0); setQuietPending(false); setQuietCount(0); setPendingFollowUp(false); setOpenersOpen(false); setOpenerIdeas(null); setOpenerLoading(false); setOpenerUsed(false); setOpenSections({}); hintGenKey.current = null; setScreen("expectations");
    setTimeout(() => inputRef.current?.focus(), 150);
  };

  const genCustom = async () => {
    if (!customInput.trim() || customLoading) return;
    setCustomLoading(true);
    try {
      const r = await fetch(API_URL, { method:"POST", headers:{"Content-Type":"application/json"}, body:JSON.stringify({ model:"claude-sonnet-4-6", max_tokens:1000, messages:[{role:"user",content:buildCustomPersonaPrompt(customInput)}] }) });
      const d = await r.json(); const p = JSON.parse((d.content?.[0]?.text||"").replace(/```json|```/g,"").trim());
      pick({ id:"custom_"+Date.now(), emoji:"🎯", ...p }, "custom");
    } catch(e) { console.error(e); }
    setCustomLoading(false);
  };

  const send = async () => {
    if (!input.trim() || loading || simComplete) return;
    const txt = input.trim();
    if (mode === "sim") { const w = checkOvershare(txt); if (w.length) setWarnings(p => [...p, ...w.map(x=>({text:x,turn:exchangeCount+1}))]); if (looksLikeLink(txt)) setLinkSent(true); }
    const upd = [...messages, { role:"user", content:txt }];
    setMessages(upd); setInput(""); setLoading(true);
    const nc = exchangeCount + 1; setExchangeCount(nc);
    const wasQuiet = pendingFollowUp;
    if (!wasQuiet && shouldGoQuiet(txt)) {
      setQuietCount(c => c + 1);
      await new Promise(r => setTimeout(r, 1100));
      setMessages(p => [...p, pickQuietEvent(situation.personaName)]);
      setQuietPending(true);
      setLoading(false);
      if (nc >= MAX) setSimComplete(true);
      return;
    }
    try {
      let sys = mode === "qualify" ? buildQualifyPrompt(linkType, situation, lang, difficulty) : buildSimPrompt(linkType, situation, contextType, agentType, lang, difficulty);
      if (wasQuiet) { setPendingFollowUp(false); sys += `\n\nFOLLOW-UP CONTEXT: You went quiet for a while after their last message. They are now following up. React like a real person who got busy and is just now seeing it. If the follow-up is light, short, and friendly, warm back up. If it's pushy, salesy, or a paragraph, stay cool or barely respond.`; }
      const r = await fetch(API_URL, { method:"POST", headers:{"Content-Type":"application/json"}, body:JSON.stringify({ model:"claude-sonnet-4-6", max_tokens:1000, system:sys, messages:toApiMessages(upd) }) });
      const d = await r.json();
      const reply = d.content?.[0]?.text || "...";
      setMessages(p => [...p, { role:"assistant", content:reply }]);
      if (nc >= MAX) setSimComplete(true);
      if (mode === "sim" && closing && looksLikeClose(txt)) setAutoCloseArmed(true);
    } catch(e) { setMessages(p => [...p, { role:"assistant", content:"..." }]); console.error(e); }
    setLoading(false);
  };

  const score = async () => {
    setScoringLoading(true); setScreen("score"); setOpenSections({});
    try {
      const prompt = mode === "qualify" ? buildQualifyScoringPrompt(linkType, situation, messages) : buildSimScoringPrompt(linkType, situation, contextType, messages, agentType);
      const r = await fetch(API_URL, { method:"POST", headers:{"Content-Type":"application/json"}, body:JSON.stringify({ model:"claude-sonnet-4-6", max_tokens:1000, messages:[{role:"user",content:prompt}] }) });
      const d = await r.json(); const p = JSON.parse((d.content?.[0]?.text||"").replace(/```json|```/g,"").trim());
      setScoring(p); setStats(s => ({ played:s.played+1, passed:s.passed+(p.passed?1:0), total:s.total+p.total_score }));
    } catch(e) { setScoring({error:true}); console.error(e); }
    setScoringLoading(false);
  };

  // After the agent closes clean with a thank-you (post-link), let the prospect's
  // last reply land, then auto-roll into coaching.
  useEffect(() => {
    if (!autoCloseArmed || loading || screen !== "sim") return;
    const t = setTimeout(() => { setAutoCloseArmed(false); score(); }, 1600);
    return () => clearTimeout(t);
  }, [autoCloseArmed, loading, screen]); // eslint-disable-line

  const goHome = () => { setScreen("home"); setMode(null); setLinkType(null); setContextType(null); setSituation(null); setMessages([]); setScoring(null); setWarnings([]); setCustomInput(""); setMavMessages([]); setMavInput(""); setMavContext(""); setMavTrack(null); setLinkSent(false); setClosing(false); setQuietPending(false); setQuietCount(0); setPendingFollowUp(false); setAutoCloseArmed(false); };
  const goScenarios = () => { setScreen("scenarios"); setSituation(null); setMessages([]); setScoring(null); setWarnings([]); setCustomInput(""); };
  const coachWithMav = () => {
    const who = situation?.personaName || "the prospect";
    const transcript = messages.map(m => `${m.role === "user" ? "AGENT" : who}: ${m.content}`).join("\n");
    const scoreLine = scoring && !scoring.error ? `\n\nScore given: ${scoring.total_score}/50, ${scoring.passed ? "passed" : "needs work"}.${scoring.coaching_tip ? ` Top fix flagged: ${scoring.coaching_tip}` : ""}` : "";
    setMavContext(`Prospect: ${who}${situation?.personaTrait ? `, ${situation.personaTrait}` : ""}. Link being worked: ${linkType}.\n\nTranscript:\n${transcript}${scoreLine}`);
    setMavTrack(agentType); setMavMessages([]); setMavInput(""); setScreen("mav");
  };

  const startSpotter = () => {
    const order = [...Array(SPOTTER_PROFILES.length).keys()].sort(() => Math.random() - 0.5);
    setSpotterOrder(order); setSpotterIndex(0); setSpotterAnswer(null); setSpotterRevealed(false);
    setSpotterStats({correct:0,total:0}); setScreen("spotter");
  };

  // Generate a fresh random qualify scenario and jump into it
  const regenScenario = async () => {
    if (regenLoading) return;
    setRegenLoading(true);
    try {
      const r = await fetch(API_URL, { method:"POST", headers:{"Content-Type":"application/json"}, body:JSON.stringify({ model:"claude-sonnet-4-6", max_tokens:600, messages:[{role:"user",content:buildQualifyScenarioPrompt(linkType)}] }) });
      const d = await r.json(); const p = JSON.parse((d.content?.[0]?.text||"").replace(/```json|```/g,"").trim());
      setRegenLoading(false);
      pick({ id:"qregen_"+Date.now(), emoji:"🎲", ...p }, "qualify");
    } catch(e) { console.error(e); setRegenLoading(false); }
  };

  // Mav AI coach chat
  const sendMav = async () => {
    if (!mavInput.trim() || mavLoading) return;
    const txt = mavInput.trim();
    const upd = [...mavMessages, { role:"user", content:txt }];
    setMavMessages(upd); setMavInput(""); setMavLoading(true);
    try {
      const r = await fetch(API_URL, { method:"POST", headers:{"Content-Type":"application/json"}, body:JSON.stringify({ model:"claude-sonnet-4-6", max_tokens:700, system:buildMavPrompt(lang, mavContext, mavTrack), messages:upd.map(m=>({role:m.role==="user"?"user":"assistant",content:m.content})) }) });
      const d = await r.json();
      setMavMessages(p => [...p, { role:"assistant", content:d.content?.[0]?.text||"..." }]);
    } catch(e) { setMavMessages(p => [...p, { role:"assistant", content:"Something went wrong, try again." }]); console.error(e); }
    setMavLoading(false);
  };

  const spotterSubmit = (ans) => { setSpotterAnswer(ans); setSpotterRevealed(true); };
  const spotterNext = () => {
    const profile = SPOTTER_PROFILES[spotterOrder[spotterIndex]];
    const correct = spotterAnswer === profile.answer;
    setSpotterStats(s => ({ correct:s.correct+(correct?1:0), total:s.total+1 }));
    if (spotterIndex + 1 >= spotterOrder.length) { setScreen("spotterDone"); }
    else { setSpotterIndex(spotterIndex+1); setSpotterAnswer(null); setSpotterRevealed(false); }
  };

  // ─── COLORS ───
  const cl = THEMES[theme];
  const themBubbleText = theme === "light" ? "#000" : "#fff";
  const sf = SF;

  // ─── Shared interactive primitives (the Playbook is the model) ───
  // One definition so every screen reveals, chevrons, and script bubbles
  // look and behave the same. Scripts ALWAYS render in a send bubble.
  const Chevron = ({ open, color }) => (
    <svg width="11" height="11" viewBox="0 0 12 12" fill="none" style={{ transition:"transform .25s", transform:open?"rotate(180deg)":"rotate(0)", flexShrink:0 }}>
      <path d="M2 4l4 4 4-4" stroke={open?(color||cl.accent):cl.textDim} strokeWidth="1.4" strokeLinecap="round" strokeLinejoin="round"/>
    </svg>
  );
  const ScriptBubble = ({ label, line }) => (
    <div style={{ marginBottom:12 }}>
      {label && <div style={{ fontSize:12, fontWeight:600, color:cl.textSoft, marginBottom:6, letterSpacing:0.1 }}>{label}</div>}
      <div style={{ display:"flex", justifyContent:"flex-end" }}>
        <div style={{ maxWidth:"88%", background:"#0A84FF", color:"#fff", fontSize:14.5, lineHeight:1.5, padding:"10px 14px", borderRadius:"18px 18px 6px 18px", letterSpacing:-0.1, whiteSpace:"pre-wrap" }}>{line}</div>
      </div>
    </div>
  );
  // Revealed body text in the Playbook style: soft text behind a left accent border.
  const RevealText = ({ children, color }) => (
    <div style={{ fontSize:13.5, color:cl.textSoft, lineHeight:1.7, padding:"0 16px 12px 12px", marginLeft:15, borderLeft:`2px solid ${(color||cl.accent)}33`, whiteSpace:"pre-wrap" }}>{children}</div>
  );

  // ══ HOME ══
  // ══ WELCOME GATE ══
  // Full screen (not the phone frame). Sets name + track for the whole app, so
  // the Sim, Qualifier, Mav AI, and Playbook never ask "student or licensed".
  // Not stored, so a fresh session always lands here and re-asks the name.
  if (!agentType) return (
    <div style={{ minHeight:"100vh", width:"100%", boxSizing:"border-box", background:cl.bg, color:cl.text, fontFamily:SF, display:"flex", alignItems:"flex-start", justifyContent:"center", overflowY:"auto", padding:"40px 22px 28px" }}>
      <style>{`::-webkit-scrollbar{width:0;height:0;display:none}*{scrollbar-width:none;-ms-overflow-style:none}`}</style>
      <div style={{ width:"100%", maxWidth:380, display:"flex", flexDirection:"column" }}>
        <img src={LOGO} alt="Mavericks" style={{ height:54, width:"auto", display:"block", margin:"0 auto 12px", objectFit:"contain" }} />
        <h1 style={{ fontSize:33, fontWeight:800, letterSpacing:-0.8, lineHeight:1.1, textAlign:"center", marginBottom:6, color:cl.heading }}>The Prospecting Lab</h1>
        <div style={{ fontSize:11.5, fontWeight:600, color:cl.textSoft, letterSpacing:2, textTransform:"uppercase", textAlign:"center", marginBottom:14 }}>AI Powered Coaching by Mavericks</div>

        <div style={{ fontSize:11.5, color:cl.textDim, lineHeight:1.4, marginBottom:18, textAlign:"center", maxWidth:340, marginLeft:"auto", marginRight:"auto" }}>
          For the best view, tap the expand icon in the top right corner for full screen.
        </div>

        <div style={{ fontSize:11, fontWeight:700, color:cl.textDim, letterSpacing:1.4, textTransform:"uppercase", marginBottom:8 }}>First, your name</div>
        <input value={welcomeName} onChange={e=>setWelcomeName(e.target.value)} placeholder="First name"
          style={{ width:"100%", boxSizing:"border-box", padding:"13px 16px", borderRadius:14, border:`1px solid ${cl.cardBorder}`, background:cl.inputBg, color:cl.text, fontSize:16, fontFamily:sf, outline:"none", marginBottom:16 }} />

        <div style={{ fontSize:11, fontWeight:700, color:cl.textDim, letterSpacing:1.4, textTransform:"uppercase", marginBottom:8 }}>Which are you?</div>
        <div style={{ display:"flex", gap:4, border:`1px solid ${cl.cardBorder}`, borderRadius:14, padding:4, marginBottom:10 }}>
          {Object.entries(AGENT_TYPES).map(([k,v]) => {
            const on = welcomeTrack === k;
            return (
              <button key={k} onClick={()=>setWelcomeTrack(k)}
                style={{ flex:1, padding:"13px 0", borderRadius:10, border:"none", cursor:"pointer", fontFamily:sf, fontSize:15, fontWeight:on?700:600, letterSpacing:0.2, transition:"all .2s", background: on ? cl.accent : "transparent", color: on ? "#fff" : cl.textSoft }}>
                {v.label}
              </button>
            );
          })}
        </div>
        <div style={{ fontSize:13, color:cl.textSoft, textAlign:"center", lineHeight:1.45, marginBottom:16, minHeight:18 }}>
          {AGENT_TYPES[welcomeTrack]?.description}
        </div>

        <button disabled={!welcomeName.trim()}
          onClick={()=>{ setAgentName(welcomeName.trim()); setAgentType(welcomeTrack); }}
          style={{ width:"100%", padding:14, borderRadius:14, border:"none", background: welcomeName.trim()?cl.accent:cl.card, color: welcomeName.trim()?"#fff":cl.textDim, fontSize:15, fontWeight:700, cursor:welcomeName.trim()?"pointer":"default", fontFamily:sf, transition:"background .2s" }}>
          Continue
        </button>
        <div style={{ fontSize:11.5, color:cl.textDim, textAlign:"center", marginTop:12, lineHeight:1.5 }}>
          {welcomeName.trim() ? "You can switch your track anytime in settings." : "Enter your name to continue."}
        </div>
      </div>
    </div>
  );

  if (screen === "home") return (
    <PhoneShell cl={cl} theme={theme}>
      <div style={{ flex:1, padding:"16px 20px", overflowY:"auto" }}>
        <div style={{ display:"flex", justifyContent:"flex-end", alignItems:"center", marginBottom:-8, position:"relative" }}>
          <span style={{ marginRight:8, fontSize:10, fontWeight:800, color:cl.accent, background:cl.accent+"1f", padding:"3px 9px", borderRadius:6, letterSpacing:1.5 }}>BETA</span>
          <button onClick={()=>setSettingsOpen(o=>!o)}
            style={{ display:"flex", alignItems:"center", gap:7, background:cl.card, border:`1px solid ${cl.cardBorder}`, borderRadius:20, padding:"7px 12px", cursor:"pointer", fontFamily:sf, fontSize:12, fontWeight:600, color:cl.textSoft }}>
            <span style={{ width:8, height:8, borderRadius:"50%", background: theme==="mavericks" ? "#f06a1e" : theme==="mavherick" ? "#e6b93f" : theme==="light" ? "#aeaeb2" : "#6c6c70", flexShrink:0 }} />
            <svg width="14" height="14" viewBox="0 0 14 14" fill="none"><circle cx="7" cy="7" r="2.2" stroke={cl.textSoft} strokeWidth="1.2"/><path d="M7 1v1.6M7 11.4V13M1 7h1.6M11.4 7H13M2.8 2.8l1.1 1.1M10.1 10.1l1.1 1.1M2.8 11.2l1.1-1.1M10.1 3.9l1.1-1.1" stroke={cl.textSoft} strokeWidth="1.1" strokeLinecap="round"/></svg>
            <svg width="9" height="9" viewBox="0 0 12 12" fill="none" style={{ transition:"transform .2s", transform:settingsOpen?"rotate(180deg)":"rotate(0)" }}><path d="M2 4l4 4 4-4" stroke={cl.textSoft} strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </button>
          {settingsOpen && (
            <div style={{ position:"absolute", top:44, right:0, zIndex:60, width:230, background:cl.card, border:`1px solid ${cl.cardBorder}`, borderRadius:16, padding:"12px 10px", boxShadow:cl.shellShadow }}>
              <div style={{ fontSize:9.5, fontWeight:700, color:cl.textDim, letterSpacing:1.6, textTransform:"uppercase", padding:"0 6px 6px" }}>Theme</div>
              {[{k:"dark",label:"Dark",dot:"#6c6c70"},{k:"light",label:"Light",dot:"#aeaeb2"},{k:"mavericks",label:"Mavericks",dot:"#f06a1e"},{k:"mavherick",label:"MavHERick",dot:"#e6b93f"}].map(t=>{
                const on = theme===t.k;
                return (
                  <button key={t.k} onClick={()=>setTheme(t.k)}
                    style={{ width:"100%", display:"flex", alignItems:"center", gap:9, background:on?cl.bg:"transparent", border:"none", borderRadius:10, padding:"9px 10px", cursor:"pointer", fontFamily:sf, fontSize:13, fontWeight:on?700:500, color:cl.text, textAlign:"left" }}>
                    <span style={{ width:9, height:9, borderRadius:"50%", background:t.dot, flexShrink:0 }} />
                    <span style={{ flex:1 }}>{t.label}</span>
                    {on && <svg width="13" height="13" viewBox="0 0 14 14" fill="none"><path d="M2.5 7.5l3 3 6-7" stroke={cl.accent} strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"/></svg>}
                  </button>
                );
              })}
              <div style={{ height:1, background:cl.separator, margin:"8px 6px" }} />
              <div style={{ fontSize:9.5, fontWeight:700, color:cl.textDim, letterSpacing:1.6, textTransform:"uppercase", padding:"0 6px 6px" }}>Prospect language</div>
              {[{k:"en",code:"EN",label:"English"},{k:"fil",code:"FI",label:"Filipino"},{k:"es",code:"SP",label:"Spanish"}].map(o=>{
                const locked = o.k !== "en";
                const on = lang===o.k && !locked;
                return (
                  <button key={o.k} onClick={()=>{ if(!locked) setLang(o.k); }}
                    style={{ width:"100%", display:"flex", alignItems:"center", gap:9, background:on?cl.bg:"transparent", border:"none", borderRadius:10, padding:"9px 10px", cursor:locked?"default":"pointer", fontFamily:sf, fontSize:13, color:locked?cl.textDim:cl.text, textAlign:"left", opacity:locked?0.5:1 }}>
                    <span style={{ fontWeight:700, width:22, flexShrink:0 }}>{o.code}</span>
                    <span style={{ flex:1, color:locked?cl.textDim:cl.textSoft, fontWeight:on?600:500 }}>{o.label}</span>
                    {locked && <span style={{ fontSize:10, fontWeight:600, color:cl.textDim, background:"rgba(255,255,255,0.06)", padding:"2px 7px", borderRadius:6 }}>Coming soon</span>}
                    {on && <svg width="13" height="13" viewBox="0 0 14 14" fill="none"><path d="M2.5 7.5l3 3 6-7" stroke={cl.accent} strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"/></svg>}
                  </button>
                );
              })}
              <div style={{ height:1, background:cl.separator, margin:"8px 6px" }} />
              <div style={{ fontSize:9.5, fontWeight:700, color:cl.textDim, letterSpacing:1.6, textTransform:"uppercase", padding:"0 6px 6px" }}>You</div>
              <div style={{ display:"flex", alignItems:"center", gap:9, padding:"2px 10px 6px" }}>
                <span style={{ width:9, height:9, borderRadius:"50%", background:cl.accent, flexShrink:0 }} />
                <span style={{ flex:1, fontSize:13, color:cl.text }}>{agentName || "Agent"} <span style={{ color:cl.textSoft }}>· {AGENT_TYPES[agentType]?.label || ""}</span></span>
              </div>
              <button onClick={()=>{ setSettingsOpen(false); setWelcomeName(""); setAgentName(""); goHome(); setAgentType(null); }}
                style={{ width:"100%", display:"flex", alignItems:"center", gap:9, background:"transparent", border:"none", borderRadius:10, padding:"9px 10px", cursor:"pointer", fontFamily:sf, fontSize:13, fontWeight:600, color:cl.accent, textAlign:"left" }}>
                <svg width="13" height="13" viewBox="0 0 14 14" fill="none"><path d="M2.2 7a4.8 4.8 0 1 1 1.3 3.3M2.2 7V4.2M2.2 7H5" stroke={cl.accent} strokeWidth="1.3" strokeLinecap="round" strokeLinejoin="round"/></svg>
                Switch name or track
              </button>
            </div>
          )}
        </div>
        <div style={{ textAlign:"center", marginBottom:32, paddingTop:4 }}>
          <img src={LOGO} alt="Mavericks" style={{ height:64, width:"auto", display:"block", margin:"0 auto 14px", objectFit:"contain" }} />
          <h1 style={{ fontSize:30, fontWeight:800, letterSpacing:-1, lineHeight:1.05, marginBottom:7, color:cl.heading }}>The Prospecting Lab</h1>
          <div style={{ fontSize:12, fontWeight:600, color:cl.textSoft, letterSpacing:4.5, textTransform:"uppercase", marginBottom:14 }}>by Mavericks</div>
          {agentName && <div style={{ fontSize:15, fontWeight:700, color:cl.text, marginBottom:12 }}>Hey {agentName} <span style={{ fontWeight:600, color:cl.textSoft }}>· {AGENT_TYPES[agentType]?.label}</span></div>}
          <p style={{ fontSize:14.5, color:cl.textSoft, lineHeight:1.5, maxWidth:300, margin:"0 auto" }}>
            Practice the conversation until it's automatic.
          </p>
          <div style={{ fontSize:13, color:cl.textSoft, lineHeight:1.6, maxWidth:320, margin:"12px auto 0", background:cl.card, border:`1px solid ${cl.cardBorder}`, borderRadius:12, padding:"12px 15px", textAlign:"center" }}>
            This tool trains you with the framework for sending FAST links and driving traffic to your page. For best results: join the MAR, work your Rolling 100 List, and send links to book appts.
          </div>
          {stats.played > 0 && (
            <div style={{ display:"flex", gap:12, justifyContent:"center", marginTop:14 }}>
              {[{v:stats.played,l:"played"},{v:stats.passed,l:"passed",color:cl.green},{v:Math.round(stats.total/stats.played)+"/50",l:"avg"}].map((s,i)=>(
                <div key={i} style={{ background:cl.card, borderRadius:14, padding:"10px 16px", textAlign:"center" }}>
                  <div style={{ fontSize:18, fontWeight:700, color:s.color||cl.text }}>{s.v}</div>
                  <div style={{ fontSize:10, color:cl.textDim, marginTop:2 }}>{s.l}</div>
                </div>
              ))}
            </div>
          )}
        </div>
        <div style={{ fontSize:13, fontWeight:600, color:cl.textDim, marginBottom:12 }}>Choose your training</div>
        {[
          { key:"playbook", label:"The Playbook", icon:"📖", desc:"New here? Learn the framework first. Your cheat sheet, anytime", col:cl.yellow },
          { key:"sim", label:"Conversation Sim", icon:"💬", desc:"Practice sending your link in a real text conversation", col:cl.accent },
          { key:"qualify", label:"Prospect Qualifier", icon:"🎯", desc:"Learn to identify if someone is a real prospect", col:cl.purple },
          { key:"spotter", label:"Signal Spotter", icon:"👁️", desc:"Flash-card training, spot the right link from a profile", col:cl.orange },
          { key:"mav", label:"Run with Mav AI", icon:"⚡", desc:"Stuck on a real conversation? Run it by Mav AI for a framework answer", col:cl.green },
        ].map(m => (
          <button key={m.key} onClick={() => { setMode(m.key); m.key === "playbook" ? setScreen("playbook") : m.key === "spotter" ? startSpotter() : m.key === "mav" ? (setMavContext(""), setMavTrack(agentType), setMavGreeting(MAV_NAME_GREETINGS[Math.floor(Math.random()*MAV_NAME_GREETINGS.length)](agentName || "there")), setMavMessages([]), setScreen("mav")) : setScreen("linkType"); }}
            style={{ width:"100%", display:"flex", alignItems:"center", gap:14, background:cl.card, border:`1px solid ${m.key==="mav"?cl.green+"30":m.key==="playbook"?cl.yellow+"40":cl.cardBorder}`, borderRadius:16, padding:"16px 18px", marginBottom:8, cursor:"pointer", textAlign:"left", fontFamily:sf, color:cl.text, transition:"transform 0.1s" }}
            onMouseDown={e=>e.currentTarget.style.transform="scale(0.98)"} onMouseUp={e=>e.currentTarget.style.transform="scale(1)"} onMouseLeave={e=>e.currentTarget.style.transform="scale(1)"}
          >
            <div style={{ width:46, height:46, borderRadius:14, background:`${m.col}18`, display:"flex", alignItems:"center", justifyContent:"center", fontSize:22, flexShrink:0 }}>{m.key==="mav" ? <img src={MAV_LOGO} alt="Mav AI" style={{ width:30, height:30, objectFit:"contain" }} /> : m.icon}</div>
            <div style={{ flex:1 }}>
              <div style={{ fontSize:16, fontWeight:700, letterSpacing:-0.3 }}>{m.label}</div>
              <div style={{ fontSize:13, color:cl.textSoft, marginTop:2, lineHeight:1.4 }}>{m.desc}</div>
            </div>
            <svg width="8" height="14" viewBox="0 0 8 14" style={{flexShrink:0,opacity:0.3}}><path d="M1 1l6 6-6 6" stroke={cl.text} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </button>
        ))}

        {/* Recording notice */}
        <div style={{ marginTop:16, padding:"12px 14px", background:cl.card, borderRadius:12, display:"flex", alignItems:"flex-start", gap:8 }}>
          <span style={{ fontSize:13, flexShrink:0, marginTop:1 }}>🎙️</span>
          <div style={{ fontSize:12, color:cl.textSoft, lineHeight:1.5 }}>
            Heads up: your practice conversations are recorded. We use them to train Mavericks AI to handle the real objections that come from real agents in the field.
          </div>
        </div>
      </div>
    </PhoneShell>
  );

  // ══ PLAYBOOK / CHEAT SHEET ══
  if (screen === "playbook") {
    const resolve = (sec) => (pbTrack === "student" && sec.student) ? { ...sec, ...sec.student } : sec;
    const tracked = PLAYBOOK_SECTIONS.map((sec, origIdx) => ({ sec, origIdx }));
    const overviewItem = pbPath === "recruit" ? null : tracked.find(({sec}) => sec.overview && (!sec.track || sec.track === pbTrack));
    const oneRule = tracked.find(({sec}) => sec.spine === "top");
    const killsItem = tracked.find(({sec}) => sec.spine === "bottom");
    const pathSections = tracked.filter(({sec}) => !sec.overview && !sec.spine && (pbPath === "recruit" ? sec.path === "recruit" : !sec.path) && (!sec.track || sec.track === pbTrack));
    const coreSections = [oneRule, ...pathSections, killsItem].filter(Boolean);
    const pathKeys = coreSections.map(({origIdx}) => "pb" + origIdx);
    const openedCount = pathKeys.filter(k => openSections[k]).length;
    const pct = pathKeys.length ? Math.round(openedCount / pathKeys.length * 100) : 0;
    const renderBody = (sec, keyPrefix) => (
      <div style={{ padding:"0 18px 16px" }}>
        {sec.intro && (()=>{
          const ik = keyPrefix + "_intro";
          const iopen = !!openSections[ik];
          return (
            <div style={{ borderBottom:(sec.scripts||sec.points)?`1px solid ${cl.separator}`:"none" }}>
              <button onClick={()=>setOpenSections(s=>({...s,[ik]:!s[ik]}))}
                style={{ width:"100%", background:"none", border:"none", cursor:"pointer", padding:"12px 0", display:"flex", alignItems:"center", gap:9, fontFamily:sf, textAlign:"left" }}>
                <div style={{ width:6, height:6, borderRadius:"50%", flexShrink:0, background: iopen?cl.accent:"transparent", border:`1.5px solid ${cl.accent}`, transition:"background .2s" }} />
                <div style={{ flex:1, fontSize:14, fontWeight:600, color:iopen?cl.accent:cl.text, lineHeight:1.4, fontFamily:SF, letterSpacing:0.2, transition:"color .2s" }}>{sec.introHead || "Why this matters"}</div>
                <svg width="10" height="10" viewBox="0 0 12 12" fill="none" style={{ transition:"transform .25s", transform:iopen?"rotate(180deg)":"rotate(0)", flexShrink:0 }}><path d="M2 4l4 4 4-4" stroke={iopen?cl.accent:cl.textDim} strokeWidth="1.4" strokeLinecap="round" strokeLinejoin="round"/></svg>
              </button>
              {iopen && <div style={{ fontSize:13.5, color:cl.textSoft, lineHeight:1.7, padding:"0 0 12px 12px", marginLeft:15, borderLeft:`2px solid ${cl.accent}33` }}>{sec.intro}</div>}
            </div>
          );
        })()}
        {sec.scripts && (()=>{
          const parse = (label) => {
            const m = label && label.match(/^(.*?)\s*\(([^)]+)\)\s*$/);
            return m ? { base: m[1].trim(), variant: m[2].trim() } : { base: label, variant: null };
          };
          const isExtra = (label) => label && (/^After:/i.test(label) || /^If they ask/i.test(label));
          const shortLabel = (label) => label.replace(/^After:\s*/i,"").replace(/^If they ask what it is$/i,"what is it?").replace(/,\s*then stop/i,"");
          const mainScripts = sec.scripts.filter(s=>!isExtra(s.label));
          const extras = sec.scripts.filter(s=>isExtra(s.label));
          const groups = [];
          mainScripts.forEach((s)=>{
            const { base, variant } = parse(s.label);
            const last = groups[groups.length-1];
            if (last && last.base === base && variant) last.items.push({ ...s, variant });
            else groups.push({ base, items:[{ ...s, variant }] });
          });
          const ekey = keyPrefix + "::extras";
          const esel = scriptVariant[ekey];
          return (<>
            {groups.map((g, gi)=>{
              if (g.items.length < 2) {
                return (
                  <div key={gi} style={{ marginTop:gi===0?14:0 }}>
                    <ScriptBubble label={g.items[0].label} line={g.items[0].line} />
                  </div>
                );
              }
              const vkey = keyPrefix + "::" + gi;
              const sel = Math.min(scriptVariant[vkey] || 0, g.items.length-1);
              return (
                <div key={gi} style={{ marginTop:gi===0?14:0, marginBottom:12 }}>
                  <div style={{ fontSize:12, fontWeight:600, color:cl.textSoft, marginBottom:6, letterSpacing:0.1 }}>{g.base}</div>
                  <div style={{ display:"flex", flexWrap:"wrap", gap:5, marginBottom:8 }}>
                    {g.items.map((it, vi)=>(
                      <button key={vi} onClick={()=>setScriptVariant(s=>({ ...s, [vkey]: vi }))}
                        style={{ padding:"5px 11px", borderRadius:20, border:`1px solid ${sel===vi ? "#0A84FF" : cl.cardBorder}`, background: sel===vi ? "#0A84FF" : "transparent", color: sel===vi ? "#fff" : cl.textSoft, fontSize:12, fontWeight:600, cursor:"pointer", fontFamily:sf, letterSpacing:0.1, transition:"all .15s" }}>
                        {it.variant}
                      </button>
                    ))}
                  </div>
                  <ScriptBubble label={null} line={g.items[sel].line} />
                </div>
              );
            })}
            {extras.length > 0 && (
              <div style={{ marginTop:16, paddingTop:14, borderTop:`1px solid ${cl.separator}` }}>
                <div style={{ fontSize:11, fontWeight:700, color:cl.textDim, letterSpacing:1, textTransform:"uppercase", marginBottom:8 }}>Follow-ups &amp; FAQs</div>
                <div style={{ display:"flex", flexWrap:"wrap", gap:5, marginBottom: esel!=null?10:0 }}>
                  {extras.map((it, vi)=>{
                    const on = esel===vi;
                    return (
                      <button key={vi} onClick={()=>setScriptVariant(s=>({ ...s, [ekey]: on?null:vi }))}
                        style={{ padding:"5px 11px", borderRadius:20, border:`1px solid ${on ? "#0A84FF" : cl.cardBorder}`, background: on ? "#0A84FF" : "transparent", color: on ? "#fff" : cl.textSoft, fontSize:12, fontWeight:600, cursor:"pointer", fontFamily:sf, letterSpacing:0.1, transition:"all .15s" }}>
                        {shortLabel(it.label)}
                      </button>
                    );
                  })}
                </div>
                {esel!=null && extras[esel] && <ScriptBubble label={null} line={extras[esel].line} />}
              </div>
            )}
          </>);
        })()}
        {sec.points && sec.points.map((pt,pi)=>{
          const head = sec.heads && sec.heads[pi];
          // No headline authored (short punch lists like "What kills you"): plain line.
          if (!head) return (
            <div key={pi} style={{ fontSize:13.5, color:cl.textSoft, lineHeight:1.6, padding:"10px 0", borderTop: pi>0?`1px solid ${cl.separator}`:"none" }}>{pt}</div>
          );
          // Headline authored: tappable punch line, full sentence revealed underneath.
          const pk = keyPrefix + "_p" + pi;
          const popen = !!openSections[pk];
          return (
            <div key={pi} style={{ borderTop: (pi>0||sec.scripts)?`1px solid ${cl.separator}`:"none", marginTop:pi===0&&sec.scripts?14:0 }}>
              <button onClick={()=>setOpenSections(s=>({...s,[pk]:!s[pk]}))}
                style={{ width:"100%", background:"none", border:"none", cursor:"pointer", padding:"12px 0", display:"flex", alignItems:"center", gap:9, fontFamily:sf, textAlign:"left" }}>
                <div style={{ width:6, height:6, borderRadius:"50%", flexShrink:0, background: popen?cl.accent:"transparent", border:`1.5px solid ${cl.accent}`, transition:"background .2s" }} />
                <div style={{ flex:1, fontSize:14, fontWeight:600, color:popen?cl.accent:cl.text, lineHeight:1.4, letterSpacing:0.1, transition:"color .2s" }}>{head}</div>
                <svg width="10" height="10" viewBox="0 0 12 12" fill="none" style={{ transition:"transform .25s", transform:popen?"rotate(180deg)":"rotate(0)", flexShrink:0 }}><path d="M2 4l4 4 4-4" stroke={popen?cl.accent:cl.textDim} strokeWidth="1.4" strokeLinecap="round" strokeLinejoin="round"/></svg>
              </button>
              {popen && <div style={{ fontSize:13.5, color:cl.textSoft, lineHeight:1.7, padding:"0 0 12px 12px", marginLeft:15, borderLeft:`2px solid ${cl.accent}33`, whiteSpace:"pre-wrap" }}>{pt}</div>}
            </div>
          );
        })}
      </div>
    );
    return (
    <PhoneShell cl={cl} theme={theme}>
      <div style={{ flex:1, padding:"16px 20px", overflowY:"auto" }}>
        <BackBtn onClick={goHome} label="Home" cl={cl} />
        <div style={{ display:"inline-block", padding:"5px 12px", borderRadius:8, background:cl.orangeBg, color:cl.orange, fontSize:12, fontWeight:600, marginTop:16, marginBottom:8 }}>
          FAST Link Framework
        </div>
        <h2 style={{ fontSize:24, fontWeight:800, letterSpacing:-0.5, marginBottom:18, color:cl.heading }}>The Playbook</h2>

        {/* Identity is a set-once setting, kept quiet so EFA/Recruiting stays the focus */}
        <div style={{ display:"flex", justifyContent:"center", marginBottom:12 }}>
          <button onClick={()=>setPbTrack(pbTrack==="student"?"licensed":"student")}
            style={{ display:"inline-flex", alignItems:"center", gap:5, padding:"4px 6px", border:"none", background:"none", cursor:"pointer", fontFamily:sf, fontSize:12.5, color:cl.textSoft, letterSpacing:0.1 }}>
            Viewing as <span style={{ color:cl.text, fontWeight:600 }}>{pbTrack==="student"?"Student":"Licensed"}</span>
            <Chevron open={false} />
          </button>
        </div>
        {/* Path tabs: EFA vs Recruiting, the primary choice */}
        <div style={{ display:"flex", gap:4, border:`1px solid ${cl.cardBorder}`, borderRadius:12, padding:4, marginBottom:10 }}>
          {[{k:"efa",label:"EFA"},{k:"recruit",label:"Recruiting"}].map(t=>(
            <button key={t.k} onClick={()=>setPbPath(t.k)}
              style={{ flex:1, padding:"13px 0", borderRadius:9, border:"none", cursor:"pointer", fontFamily:sf, fontSize:14, fontWeight:600, letterSpacing:0.3, transition:"all .2s",
                background: pbPath===t.k ? cl.accent : "transparent",
                color: pbPath===t.k ? "#fff" : cl.textSoft }}>
              {t.label}
            </button>
          ))}
        </div>
        <div style={{ fontSize:11.5, color:cl.textDim, marginBottom:14, lineHeight:1.5, textAlign:"center", letterSpacing:0.2 }}>
          {pbTrack==="student"?"Student":"Licensed"} track, {pbPath==="recruit"?"recruiting":"EFA"} playbook. Only the parts that are yours.
        </div>

        {/* Progress: fills as you work through the path */}
        <div style={{ marginBottom:18 }}>
          <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:7 }}>
            <span style={{ fontSize:10, fontWeight:700, color:cl.textDim, letterSpacing:1.5, textTransform:"uppercase" }}>Your progress</span>
            <span style={{ fontSize:11.5, fontWeight:600, color: openedCount ? cl.accent : cl.textDim, fontVariantNumeric:"tabular-nums" }}>{openedCount} of {pathKeys.length}</span>
          </div>
          <div style={{ height:6, borderRadius:3, background:cl.cardBorder, overflow:"hidden" }}>
            <div style={{ height:"100%", width:`${pct}%`, background:cl.accent, borderRadius:3, transition:"width .35s ease" }} />
          </div>
        </div>

        {/* Overview: student-only start-here card */}
        {overviewItem && (()=>{
          const key = "pbOverview";
          const open = !!openSections[key];
          return (
            <div style={{ marginBottom:16 }}>
              <div style={{ background:cl.card, borderRadius:16, border:`1px solid ${cl.cardBorder}`, overflow:"hidden" }}>
                <button onClick={()=>setOpenSections(s=>({...s,[key]:!s[key]}))}
                  style={{ width:"100%", background:"none", border:"none", cursor:"pointer", padding:"16px 18px", display:"flex", alignItems:"center", gap:14, fontFamily:sf, textAlign:"left" }}>
                  <div style={{ flex:1 }}>
                    <div style={{ fontSize:9.5, fontWeight:700, color:cl.textDim, letterSpacing:1.8, textTransform:"uppercase", marginBottom:5 }}>Start here</div>
                    <div style={{ fontFamily:SF, fontSize:18, fontWeight:600, color:cl.text, letterSpacing:0.1 }}>{overviewItem.sec.title}</div>
                  </div>
                  <svg width="11" height="11" viewBox="0 0 12 12" fill="none" style={{ transition:"transform .25s", transform:open?"rotate(180deg)":"rotate(0)", flexShrink:0 }}>
                    <path d="M2 4l4 4 4-4" stroke={cl.textDim} strokeWidth="1.4" strokeLinecap="round" strokeLinejoin="round"/>
                  </svg>
                </button>
                {open && renderBody(overviewItem.sec, "pbOverview")}
              </div>
            </div>
          );
        })()}

        {/* Numbered core path, grouped by phase */}
        {coreSections.map(({sec, origIdx}, n) => {
          const view = resolve(sec);
          const key = "pb" + origIdx;
          const open = !!openSections[key];
          const showPhase = sec.phase && (n === 0 || coreSections[n-1].sec.phase !== sec.phase);
          return (
            <div key={origIdx}>
              {showPhase && (
                <div style={{ display:"flex", alignItems:"center", gap:8, margin:"22px 2px 10px" }}>
                  <div style={{ width:5, height:5, borderRadius:1.5, background:cl.accent, flexShrink:0 }} />
                  <div style={{ fontSize:9.5, fontWeight:700, color:cl.accent, letterSpacing:2, textTransform:"uppercase", flexShrink:0 }}>{sec.phase}</div>
                  <div style={{ flex:1, height:1, background:cl.separator }} />
                </div>
              )}
              <div style={{ background: open ? `${cl.accent}0d` : cl.card, borderRadius:14, marginBottom:8, border:`1px solid ${open ? cl.accent : cl.cardBorder}`, overflow:"hidden", transition:"background .2s, border-color .2s" }}>
                <button onClick={()=>setOpenSections(s=>({...s,[key]:!s[key]}))}
                  style={{ width:"100%", background:"none", border:"none", cursor:"pointer", padding:"15px 16px", display:"flex", alignItems:"center", gap:13, fontFamily:sf, textAlign:"left" }}>
                  <div style={{ width:30, height:30, borderRadius:9, flexShrink:0, display:"flex", alignItems:"center", justifyContent:"center", background:`${cl.accent}1f`, border:`1px solid ${cl.accent}${open?"":"00"}`, transition:"border-color .2s", fontSize:16 }}>{view.emoji}</div>
                  <div style={{ flex:1, fontFamily:SF, fontSize:17, fontWeight:600, color:cl.text, letterSpacing:0.1, lineHeight:1.25 }}>{view.title}</div>
                  <svg width="11" height="11" viewBox="0 0 12 12" fill="none" style={{ transition:"transform .25s", transform:open?"rotate(180deg)":"rotate(0)", flexShrink:0 }}>
                    <path d="M2 4l4 4 4-4" stroke={open?cl.accent:cl.textDim} strokeWidth="1.4" strokeLinecap="round" strokeLinejoin="round"/>
                  </svg>
                </button>
                {open && renderBody(view, key)}
              </div>
            </div>
          );
        })}

        <button onClick={()=>{setMode("sim");setScreen("linkType");}}
          style={{ width:"100%", padding:16, borderRadius:12, border:"none", background:cl.text, color:cl.bg, fontSize:14, fontWeight:600, letterSpacing:0.3, cursor:"pointer", fontFamily:sf, marginTop:26, marginBottom:8 }}>
          Start training
        </button>
      </div>
    </PhoneShell>
    );
  }

  // ══ AGENT TYPE ══
  if (screen === "agentType") return (
    <PhoneShell cl={cl} theme={theme}>
      <div style={{ flex:1, padding:"16px 20px", overflowY:"auto" }}>
        <BackBtn onClick={goHome} label="Home" cl={cl} />
        <h2 style={{ fontSize:26, fontWeight:800, letterSpacing:-0.5, marginTop:16, marginBottom:6, color:cl.heading }}>Are you a...</h2>
        <p style={{ fontSize:14, color:cl.textSoft, marginBottom:24 }}>This changes the script you'll train on.</p>
        {Object.entries(AGENT_TYPES).map(([k,v]) => (
          <button key={k} onClick={()=>{setAgentType(k);setScreen("linkType")}}
            style={{ width:"100%", background:cl.card, border:`1px solid ${cl.cardBorder}`, borderRadius:16, padding:"20px 18px", marginBottom:8, cursor:"pointer", textAlign:"left", fontFamily:sf, color:cl.text }}
            onMouseDown={e=>e.currentTarget.style.transform="scale(0.98)"} onMouseUp={e=>e.currentTarget.style.transform="scale(1)"} onMouseLeave={e=>e.currentTarget.style.transform="scale(1)"}
          >
            <div style={{ fontSize:18, fontWeight:700, letterSpacing:-0.3 }}>{v.label}</div>
            <div style={{ fontSize:13, color:cl.textSoft, marginTop:4 }}>{v.description}</div>
          </button>
        ))}
      </div>
    </PhoneShell>
  );

  // ══ LINK TYPE ══
  if (screen === "linkType") return (
    <PhoneShell cl={cl} theme={theme}>
      <div style={{ flex:1, padding:"16px 20px", overflowY:"auto" }}>
        <BackBtn onClick={goHome} cl={cl} />
        <div style={{ display:"inline-block", padding:"5px 12px", borderRadius:8, background:mode==="qualify"?cl.purpleBg:cl.orangeBg, color:mode==="qualify"?cl.purple:cl.orange, fontSize:12, fontWeight:600, marginTop:16, marginBottom:8 }}>
          {AGENT_TYPES[agentType]?.label} · {mode==="qualify"?"Qualifier":"Sim"}
        </div>
        <h2 style={{ fontSize:24, fontWeight:800, letterSpacing:-0.5, lineHeight:1.1, marginBottom:20, color:cl.heading }}>{mode==="qualify"?"Who are you trying to qualify?":"Pick a FAST link to practice"}</h2>
        {Object.entries(LINK_TYPES).map(([k,v]) => {
          const locked = (k === "recruit_licensed");
          const levelTag = agentType === "student"
            ? (k === "recruit_unlicensed" ? { text:"Best place to start", col:cl.green }
              : k === "recruit_licensed" ? { text:"Reaching up", col:cl.purple } : null)
            : (k === "recruit_licensed" ? { text:"Your level", col:cl.green } : null);
          return (
            <button key={k} onClick={()=>{ if (!locked) { setLinkType(k); setScreen("scenarios"); } }}
              style={{ width:"100%", background:cl.card, border:`1px solid ${locked ? "rgba(255,255,255,0.03)" : cl.cardBorder}`, borderRadius:16, padding:"16px 18px", marginBottom:8, cursor:locked?"default":"pointer", textAlign:"left", fontFamily:sf, color:locked?cl.textDim:cl.text, opacity:locked?0.5:1 }}
              onMouseDown={e=>!locked&&(e.currentTarget.style.transform="scale(0.98)")} onMouseUp={e=>e.currentTarget.style.transform="scale(1)"} onMouseLeave={e=>e.currentTarget.style.transform="scale(1)"}
            >
              <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between" }}>
                <div>
                  <div style={{ fontSize:16, fontWeight:700 }}>{v.label}</div>
                  <div style={{ fontSize:13, color:locked?cl.textDim:cl.textSoft, marginTop:2 }}>{k === "efa" ? efaGoal(agentType) : v.fullName}</div>
                </div>
                {levelTag && !locked && (
                  <div style={{ padding:"4px 10px", borderRadius:8, background:`${levelTag.col}1a`, fontSize:11, fontWeight:700, color:levelTag.col, flexShrink:0 }}>{levelTag.text}</div>
                )}
                {locked && (
                  <div style={{ padding:"4px 10px", borderRadius:8, background:"rgba(255,255,255,0.06)", fontSize:11, fontWeight:600, color:cl.textDim, flexShrink:0 }}>Coming soon</div>
                )}
              </div>
            </button>
          );
        })}
      </div>
    </PhoneShell>
  );

  // ══ SCENARIOS ══
  if (screen === "scenarios") return (
    <PhoneShell cl={cl} theme={theme}>
      <div style={{ flex:1, padding:"16px 20px", overflowY:"auto" }}>
        <BackBtn onClick={()=>setScreen("linkType")} cl={cl} />
        <div style={{ display:"inline-block", padding:"5px 12px", borderRadius:8, background:cl.orangeBg, color:cl.orange, fontSize:12, fontWeight:600, marginTop:16, marginBottom:8 }}>
          {LINK_TYPES[linkType].label} · {AGENT_TYPES[agentType]?.label}
        </div>
        <h2 style={{ fontSize:24, fontWeight:800, letterSpacing:-0.5, marginBottom:18, color:cl.heading }}>Pick Your Scenario</h2>
        {mode === "sim" && (
          <>
            <div style={{ background:cl.card, borderRadius:16, padding:18, marginBottom:20, border:`1px solid ${cl.accent}20` }}>
              <div style={{ display:"flex", alignItems:"center", gap:10, marginBottom:12 }}>
                <span style={{fontSize:20}}>🎯</span>
                <div><div style={{fontSize:15,fontWeight:700}}>Practice a Real Conversation</div><div style={{fontSize:12,color:cl.textSoft}}>Describe your actual situation</div></div>
              </div>
              <textarea value={customInput} onChange={e=>setCustomInput(e.target.value)} placeholder={`e.g. "My friend just had twins, she's a teacher..."`} rows={3}
                style={{ width:"100%", padding:"12px 14px", borderRadius:12, border:`1px solid ${cl.cardBorder}`, background:cl.phoneBg, color:cl.text, fontSize:14, fontFamily:sf, lineHeight:1.5, outline:"none", boxSizing:"border-box", resize:"none" }} />
              <button onClick={genCustom} disabled={!customInput.trim()||customLoading}
                style={{ width:"100%", padding:13, borderRadius:12, border:"none", background:customInput.trim()&&!customLoading?cl.accent:"rgba(255,255,255,0.06)", color:customInput.trim()&&!customLoading?"#fff":cl.textDim, fontSize:14, fontWeight:700, cursor:customInput.trim()&&!customLoading?"pointer":"default", fontFamily:sf, marginTop:8, display:"flex", alignItems:"center", justifyContent:"center", gap:8 }}>
                {customLoading?<><div style={{width:14,height:14,borderRadius:"50%",border:"2px solid rgba(255,255,255,0.2)",borderTopColor:"#fff",animation:"spin .6s linear infinite"}}/>Building...</>:"Start Practice"}
              </button>
            </div>
            <div style={{ display:"flex", alignItems:"center", gap:14, marginBottom:16 }}>
              <div style={{flex:1,height:1,background:cl.separator}}/><span style={{fontSize:11,color:cl.textDim}}>or pick a scenario</span><div style={{flex:1,height:1,background:cl.separator}}/>
            </div>
          </>
        )}
        {mode === "qualify" ? (
          <div style={{display:"flex",flexDirection:"column",gap:6}}>
            {(QUALIFY_SCENARIOS[linkType] || QUALIFY_SCENARIOS.efa).map(s=>(
              <button key={s.id} onClick={()=>pick(s,"qualify")}
                style={{ width:"100%", display:"flex", alignItems:"center", gap:12, background:cl.card, border:`1px solid ${cl.cardBorder}`, borderRadius:14, padding:"14px 16px", cursor:"pointer", textAlign:"left", fontFamily:sf, color:cl.text }}
                onMouseDown={e=>e.currentTarget.style.transform="scale(0.98)"} onMouseUp={e=>e.currentTarget.style.transform="scale(1)"} onMouseLeave={e=>e.currentTarget.style.transform="scale(1)"}
              >
                <span style={{fontSize:22,flexShrink:0}}>{s.emoji}</span>
                <div><div style={{fontSize:14,fontWeight:600}}>{s.title}</div><div style={{fontSize:12,color:cl.textSoft,marginTop:2,lineHeight:1.4}}>{s.setup.slice(0,80)}...</div></div>
              </button>
            ))}
            <button onClick={regenScenario} disabled={regenLoading}
              style={{ width:"100%", display:"flex", alignItems:"center", justifyContent:"center", gap:8, background:"transparent", border:`1.5px dashed ${cl.purple}55`, borderRadius:14, padding:"14px 16px", cursor:regenLoading?"default":"pointer", fontFamily:sf, color:cl.purple, fontSize:14, fontWeight:700, marginTop:4 }}>
              {regenLoading ? (
                <><div style={{width:14,height:14,borderRadius:"50%",border:`2px solid ${cl.purple}40`,borderTopColor:cl.purple,animation:"spin .6s linear infinite"}}/>Building a fresh one...</>
              ) : (
                <>🎲 Regenerate a scenario</>
              )}
            </button>
          </div>
        ) : (
          Object.entries(SIM_SCENARIOS[linkType] || SIM_SCENARIOS.efa).map(([ck,cv])=>(
            <div key={ck}>
              <div style={{ display:"flex", alignItems:"center", gap:8, margin:"22px 2px 10px" }}>
                <div style={{ width:5, height:5, borderRadius:1.5, background:cl.accent, flexShrink:0 }} />
                <div style={{ fontSize:9.5, fontWeight:700, color:cl.accent, letterSpacing:2, textTransform:"uppercase", flexShrink:0 }}>{cv.label}</div>
                <div style={{ flex:1, height:1, background:cl.separator }} />
              </div>
              {cv.scenarios.map(s=>(
                <button key={s.id} onClick={()=>pick(s,ck)}
                  style={{ width:"100%", display:"flex", alignItems:"center", gap:13, background:cl.card, border:`1px solid ${cl.cardBorder}`, borderRadius:14, marginBottom:8, padding:"15px 16px", cursor:"pointer", textAlign:"left", fontFamily:sf, color:cl.text }}
                  onMouseDown={e=>e.currentTarget.style.transform="scale(0.98)"} onMouseUp={e=>e.currentTarget.style.transform="scale(1)"} onMouseLeave={e=>e.currentTarget.style.transform="scale(1)"}
                >
                  <div style={{ width:30, height:30, borderRadius:9, flexShrink:0, display:"flex", alignItems:"center", justifyContent:"center", background:`${cl.accent}1f`, fontSize:16 }}>{s.emoji}</div>
                  <div style={{ flex:1 }}><div style={{ fontFamily:SF, fontSize:16, fontWeight:600, color:cl.text, letterSpacing:0.1, lineHeight:1.25 }}>{s.title}</div><div style={{ fontSize:12.5, color:cl.textSoft, marginTop:3, lineHeight:1.45 }}>{s.setup.slice(0,75)}...</div></div>
                  <svg width="11" height="11" viewBox="0 0 12 12" fill="none" style={{ flexShrink:0 }}><path d="M4 2l4 4-4 4" stroke={cl.textDim} strokeWidth="1.4" strokeLinecap="round" strokeLinejoin="round"/></svg>
                </button>
              ))}
            </div>
          ))
        )}
      </div>
    </PhoneShell>
  );

  // ══ RUN WITH MAV AI ══
  if (screen === "mav") {
    const suggestions = [
      "They said 'what is it?' before I sent the link",
      "How do I bridge if they're just venting about work?",
      "They asked if this is an MLM",
      "Prospect wants to book, I'm a student. What do I say?",
    ];
    return (
      <PhoneShell noScroll cl={cl} theme={theme}>
        <style>{`
          @keyframes fadeIn{from{opacity:0;transform:translateY(8px)}to{opacity:1;transform:translateY(0)}}
          @keyframes pulse{0%,100%{opacity:.3}50%{opacity:1}}
          @keyframes spin{to{transform:rotate(360deg)}}
        `}</style>
        {/* Top bar */}
        <div style={{ padding:"6px 16px 10px", background:cl.navBar, backdropFilter:"blur(20px)", borderBottom:`0.5px solid ${cl.separator}`, flexShrink:0, zIndex:10, display:"flex", alignItems:"center", justifyContent:"space-between" }}>
          <div style={{ flex:1, display:"flex", justifyContent:"flex-start" }}>
            <button onClick={goHome} style={{ background:"none", border:"none", color:cl.accent, fontSize:16, cursor:"pointer", fontFamily:sf, padding:0, display:"flex", alignItems:"center", gap:3 }}>
              <svg width="10" height="17" viewBox="0 0 10 17" fill="none"><path d="M9 1L1.5 8.5L9 16" stroke={cl.accent} strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/></svg>
            </button>
          </div>
          <div style={{ flex:"0 0 auto", textAlign:"center" }}>
            <img src={MAV_LOGO} alt="Mav AI" style={{ width:36, height:36, objectFit:"contain", margin:"0 auto 3px", display:"block" }} />
            <div style={{ fontSize:13, fontWeight:600, color:cl.text }}>Mav AI</div>
          </div>
          <div style={{ flex:1 }} />
        </div>

        {/* Messages */}
        <div style={{ flex:1, overflowY:"auto", padding:"12px", display:"flex", flexDirection:"column", gap:3 }}>
          {mavMessages.length === 0 && (
            <div style={{ animation:"fadeIn .4s ease", padding:"8px 4px" }}>
              {(!mavContext && !mavTrack) ? (
                <div style={{ textAlign:"center", marginTop:8 }}>
                  <div style={{ fontSize:18, fontWeight:800, color:cl.text, marginBottom:6, marginTop:20 }}>{mavGreeting || "Quick one, who are you?"}</div>
                  <div style={{ fontSize:14, color:cl.textSoft, lineHeight:1.5, maxWidth:300, margin:"0 auto 16px" }}>The frame and the scripts are different for each, so tell me which you are and I'll coach you the right way.</div>
                  <button onClick={()=>setMavTrack("student")} style={{ width:"100%", background:cl.card, border:`1px solid ${cl.cardBorder}`, borderRadius:14, padding:"13px 16px", marginBottom:8, cursor:"pointer", fontFamily:sf, color:cl.text, fontSize:15, fontWeight:700 }}>I'm a student</button>
                  <button onClick={()=>setMavTrack("licensed")} style={{ width:"100%", background:cl.card, border:`1px solid ${cl.cardBorder}`, borderRadius:14, padding:"13px 16px", cursor:"pointer", fontFamily:sf, color:cl.text, fontSize:15, fontWeight:700 }}>I'm a licensed agent</button>
                </div>
              ) : (
                <>
                  <div style={{ textAlign:"center", marginBottom:18, marginTop:8 }}>
                    <div style={{ fontSize:18, fontWeight:800, color:cl.text, marginBottom:6, marginTop:12 }}>{mavContext ? `Let's break down ${situation?.personaName || "that one"}` : (mavGreeting || `How can I help, ${agentName || "there"}?`)}</div>
                    <div style={{ fontSize:14, color:cl.textSoft, lineHeight:1.5, maxWidth:300, margin:"0 auto" }}>
                      {mavContext ? "I've got that whole conversation in front of me. Ask me the move on any moment, or just say go and I'll start with the biggest fix." : `Coaching you as a ${mavTrack === "licensed" ? "licensed agent" : "student"}. Stuck on what to say? Tell me the situation and I'll give you the move, using the Mavericks framework.`}
                    </div>
                  </div>
                  <div style={{ fontSize:12, color:cl.textDim, marginBottom:8 }}>Try one of these:</div>
                  {suggestions.map((s,i)=>(
                    <button key={i} onClick={()=>{ setMavInput(s); }}
                      style={{ width:"100%", textAlign:"left", background:cl.card, border:`1px solid ${cl.cardBorder}`, borderRadius:12, padding:"11px 14px", marginBottom:6, cursor:"pointer", fontFamily:sf, color:cl.text, fontSize:13, lineHeight:1.4 }}>
                      {s}
                    </button>
                  ))}
                </>
              )}
            </div>
          )}
          {mavMessages.map((m,i)=>{
            const isUser = m.role === "user";
            return (
              <div key={i} style={{ display:"flex", justifyContent:isUser?"flex-end":"flex-start", animation:"fadeIn .2s ease", marginTop:4 }}>
                <div style={{
                  maxWidth:"82%", padding:"10px 14px",
                  borderRadius: isUser ? "18px 18px 6px 18px" : "18px 18px 18px 6px",
                  background: isUser ? "#0A84FF" : cl.themBubble,
                  color: isUser ? "#fff" : themBubbleText, fontSize:15, lineHeight:1.5, whiteSpace:"pre-wrap",
                }}>{m.content}</div>
              </div>
            );
          })}
          {mavLoading && (
            <div style={{display:"flex",animation:"fadeIn .2s ease",marginTop:4}}>
              <div style={{ padding:"12px 18px", borderRadius:"18px 18px 18px 6px", background:cl.themBubble }}>
                <div style={{display:"flex",gap:4,alignItems:"center"}}>
                  {[0,1,2].map(i=>(<div key={i} style={{width:8,height:8,borderRadius:"50%",background:theme==="light"?"rgba(0,0,0,0.35)":"rgba(255,255,255,0.4)",animation:`pulse 1.2s ${i*0.15}s infinite`}}/>))}
                </div>
              </div>
            </div>
          )}
          <div ref={mavEndRef}/>
        </div>

        {/* Input */}
        <div style={{ padding:"8px 12px 4px", flexShrink:0 }}>
          <div style={{ display:"flex", gap:8, alignItems:"flex-end" }}>
            <div style={{ flex:1, display:"flex", alignItems:"center", background:cl.inputBg, borderRadius:22, border:`1px solid ${cl.cardBorder}`, padding:"0 4px 0 16px" }}>
              <input type="text" value={mavInput} onChange={e=>setMavInput(e.target.value)} onKeyDown={e=>e.key==="Enter"&&sendMav()} placeholder={(!mavTrack && !mavContext) ? "Pick student or licensed first" : "Describe the situation..."} disabled={mavLoading || (!mavTrack && !mavContext)}
                style={{ flex:1, padding:"11px 0", background:"transparent", border:"none", color:cl.text, fontSize:16, fontFamily:sf, outline:"none", letterSpacing:-0.2 }}/>
              <button onClick={sendMav} disabled={!mavInput.trim()||mavLoading}
                style={{ width:30, height:30, borderRadius:"50%", border:"none", background:mavInput.trim()?cl.green:"transparent", color:"#fff", cursor:mavInput.trim()?"pointer":"default", display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0, margin:3 }}>
                {mavInput.trim() && <svg width="14" height="14" viewBox="0 0 14 14" fill="none"><path d="M7 12V2M7 2L2.5 6.5M7 2L11.5 6.5" stroke="#fff" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>}
              </button>
            </div>
          </div>
          <div style={{ textAlign:"center", fontSize:10, color:cl.textDim, marginTop:6 }}>Trained on the Mavericks framework</div>
        </div>
      </PhoneShell>
    );
  }

  // ══ EXPECTATIONS (pre-sim scorecard) ══
  if (screen === "expectations" && situation) {
    const simCategories = [
      { title:"How you opened", points:["Warm market: catch up like a friend first","Cold: a quick bit of small talk, nothing heavy","Social media: react to their actual post","Jumping straight to business: low score"] },
      { title:"Did you follow the steps", points:["Warm up, then ask if you can run something by them, no big deal","Wait for them to say yes","Send it as a low pressure look: take a look and see if it's even for you","Close by thanking them and asking them to pass it along","Winging it or going off the steps: low score"] },
      { title:"How you sent the link", points:["Send the link and ask what they think","Do NOT explain what it is first","The link does the explaining, not you"] },
      { title:"Handling pushback", points:["Stay calm and keep it short when they push back","Use the simple line, do not argue","Over explaining or getting defensive: low score"] },
      { title:"Tight messages, good timing", points:["Short messages like real texting, no paragraphs","Warming up and taking your time is fine, a longer chat that stays engaged is good prospecting","The miss is paragraphs or explaining the link, or wandering with no direction until they fade"] },
    ];
    const qualCategories = [
      { title:"Asking good questions", points:["Did you find out their real situation by asking","Real questions, not a checklist"] },
      { title:"Actually listening", points:["Did you pick up on what they said and dig deeper","Or did you just jump to the next question"] },
      { title:"Spotting the signs", points:["Did you catch the signs they could be a fit","Money stress, a life change, hating their job, wanting more"] },
      { title:"Bridging naturally", points:["If the signs were good, did you move toward sharing something","Smooth, not forced"] },
      { title:"Did it feel real", points:["Felt like a real talk, not an interrogation"] },
    ];
    const cats = mode === "qualify" ? qualCategories : simCategories;

    return (
      <PhoneShell cl={cl} theme={theme}>
        <div style={{ flex:1, padding:"20px 20px", overflowY:"auto" }}>
          <div style={{ textAlign:"center", marginBottom:24 }}>
            <div style={{ fontSize:36, marginBottom:12 }}>📋</div>
            <h2 style={{ fontSize:22, fontWeight:800, letterSpacing:-0.5, marginBottom:6, color:cl.heading }}>Before You Start</h2>
            <p style={{ fontSize:14, color:cl.textSoft, lineHeight:1.5 }}>
              You're about to talk to <strong style={{color:cl.text}}>{situation.personaName}</strong>. Here's exactly what you're being scored on.
            </p>
          </div>

          <div style={{ fontSize:13, fontWeight:700, color:cl.textSoft, marginBottom:6 }}>5 things, 10 points each, 50 total. You need 35 to pass.</div>
          <div style={{ fontSize:12, color:cl.textDim, marginBottom:12 }}>Tap any one to see what it means.</div>

          {cats.map((cat, i) => {
            const key = "exp"+i;
            const open = !!openSections[key];
            return (
              <div key={i} style={{ background: open ? `${cl.accent}0d` : cl.card, borderRadius:14, marginBottom:8, overflow:"hidden", border:`1px solid ${open ? cl.accent : cl.cardBorder}`, transition:"background .2s, border-color .2s" }}>
                <button onClick={()=>setOpenSections(s=>({...s,[key]:!s[key]}))}
                  style={{ width:"100%", background:"none", border:"none", cursor:"pointer", padding:"14px 16px", display:"flex", alignItems:"center", gap:11, fontFamily:sf, textAlign:"left" }}>
                  <div style={{ width:26, height:26, borderRadius:8, background:`${cl.accent}1f`, border:`1px solid ${cl.accent}${open?"":"00"}`, display:"flex", alignItems:"center", justifyContent:"center", fontSize:12.5, fontWeight:700, color:cl.accent, flexShrink:0, fontVariantNumeric:"tabular-nums", transition:"border-color .2s" }}>{i+1}</div>
                  <div style={{ flex:1, fontSize:15, fontWeight:700, color:cl.text }}>{cat.title}</div>
                  <Chevron open={open} />
                </button>
                {open && (
                  <div style={{ padding:"0 16px 14px 53px" }}>
                    {cat.points.map((pt,pi)=>(
                      <div key={pi} style={{ fontSize:13.5, color:cl.textSoft, lineHeight:1.6, padding:"9px 0", borderTop: pi>0?`1px solid ${cl.separator}`:"none" }}>{pt}</div>
                    ))}
                  </div>
                )}
              </div>
            );
          })}

          {mode === "sim" && (
            <div style={{ background:cl.redBg, borderRadius:14, marginTop:4, marginBottom:8, overflow:"hidden" }}>
              <button onClick={()=>setOpenSections(s=>({...s,expRed:!s.expRed}))}
                style={{ width:"100%", background:"none", border:"none", cursor:"pointer", padding:"14px 16px", display:"flex", alignItems:"center", justifyContent:"space-between", fontFamily:sf, textAlign:"left" }}>
                <span style={{ fontSize:14, fontWeight:700, color:cl.red }}>Instant red flags</span>
                <Chevron open={openSections.expRed} color={cl.red} />
              </button>
              {openSections.expRed && <RevealText color={cl.red}>Mentioning insurance, comp plans, or licensing. Explaining what the link is before sending it. Messages over 40 words. Engaging with "is this an MLM?" instead of redirecting.</RevealText>}
            </div>
          )}

          {mode === "sim" && linkType === "recruit_licensed" && (
            <div style={{ background:cl.purpleBg, borderRadius:14, marginTop:4, marginBottom:8, overflow:"hidden" }}>
              <button onClick={()=>setOpenSections(s=>({...s,expLevel:!s.expLevel}))}
                style={{ width:"100%", background:"none", border:"none", cursor:"pointer", padding:"14px 16px", display:"flex", alignItems:"center", justifyContent:"space-between", fontFamily:sf, textAlign:"left" }}>
                <span style={{ fontSize:14, fontWeight:700, color:cl.purple }}>{agentType === "student" ? "Reaching up to a licensed agent" : "Recruit at your level"}</span>
                <Chevron open={openSections.expLevel} color={cl.purple} />
              </button>
              {openSections.expLevel && <RevealText color={cl.purple}>{agentType === "student" ? "Heads up, this is reaching up. You're a student talking to a licensed agent, so expect to get tested: how long have you been doing this, are you licensed, what do you know about the comp. That fear of being exposed is normal, and shrinking is the trap. Don't say \"I'm just a student\" and don't fake knowing the comp. Own being newer in one calm line, then be the connector: you bring in someone experienced to walk them through the details. The link and the colleague do the heavy lifting. Easier wins are with unlicensed people at your level, but if you're here, hold your ground." : "Your success rate tracks your own credibility. A big producer or a builder with a team won't move for someone who has no track record yet. You can prospect anyone, but early on you're far better off hunting agents who are beginning, producing, or established, agents at or near your level. Going after the whales too soon is a low percentage play and can burn a relationship you'll want later. Build your results first, then the big fish become realistic."}</RevealText>}
            </div>
          )}

          {mode === "sim" && agentType === "student" && (
            <div style={{ background:cl.orangeBg, borderRadius:14, marginTop:4, marginBottom:8, overflow:"hidden" }}>
              <button onClick={()=>setOpenSections(s=>({...s,expBook:!s.expBook}))}
                style={{ width:"100%", background:"none", border:"none", cursor:"pointer", padding:"14px 16px", display:"flex", alignItems:"center", justifyContent:"space-between", fontFamily:sf, textAlign:"left" }}>
                <span style={{ fontSize:14, fontWeight:700, color:cl.orange }}>{linkType === "efa" ? "Booking the field training appointment" : "If they want to book"}</span>
                <Chevron open={openSections.expBook} color={cl.orange} />
              </button>
              {openSections.expBook && <RevealText color={cl.orange}>{linkType === "efa" ? "When the prospect wants to talk, your goal is to set a field training appointment. Lock in a time, and bring your colleague as the one who'll walk them through everything, with you right there. You set it, your colleague runs it, you sit in to learn and hold the relationship. Never say \"I'm just a student\" or \"I'm still learning.\" You're the bridge, not the beginner. The miss is fumbling who they'd meet, diminishing yourself, or never actually pinning a time." : "When the prospect wants to set a time, introduce your colleague as the one who'll walk them through everything, and stay in it as the person who connected them. Never say \"I'm just a student\" or \"I'm still learning.\" You're the bridge, not the beginner. Until your license is finalized, your colleague runs the appointment with you there."}</RevealText>}
            </div>
          )}

          {mode === "qualify" && (
            <div style={{ background:cl.greenBg, borderRadius:14, marginTop:4, marginBottom:8, overflow:"hidden" }}>
              <button onClick={()=>setOpenSections(s=>({...s,expPass:!s.expPass}))}
                style={{ width:"100%", background:"none", border:"none", cursor:"pointer", padding:"14px 16px", display:"flex", alignItems:"center", justifyContent:"space-between", fontFamily:sf, textAlign:"left" }}>
                <span style={{ fontSize:14, fontWeight:700, color:cl.green }}>What passing looks like</span>
                <Chevron open={openSections.expPass} color={cl.green} />
              </button>
              {openSections.expPass && <RevealText color={cl.green}>Score 35+ AND identify at least 2 qualifying signals AND it feels like a real conversation, not a questionnaire.</RevealText>}
            </div>
          )}

          <div style={{ marginTop:16, fontSize:12, color:cl.textDim, lineHeight:1.45 }}>
            Every prospect is a fresh read, just like real life. You don't get to pick who's easy. Most are winnable if you do the basics right, some make you work.
          </div>

          <button onClick={()=>{setScreen("sim");setTimeout(()=>inputRef.current?.focus(),150);}}
            style={{ width:"100%", padding:16, borderRadius:24, border:"none", background:cl.accent, color:"#fff", fontSize:16, fontWeight:700, cursor:"pointer", fontFamily:sf, marginTop:12 }}>
            Got it, let's go
          </button>
        </div>
      </PhoneShell>
    );
  }

  // ══ SIMULATION (iMessage) ══
  if (screen === "sim" && situation) return (
    <PhoneShell noScroll cl={cl} theme={theme}>
      <style>{`
        @keyframes fadeIn{from{opacity:0;transform:translateY(8px)}to{opacity:1;transform:translateY(0)}}
        @keyframes pulse{0%,100%{opacity:.3}50%{opacity:1}}
        @keyframes spin{to{transform:rotate(360deg)}}
        @keyframes warnSlide{from{opacity:0;transform:translateX(-8px)}to{opacity:1;transform:translateX(0)}}
      `}</style>
      {/* iMessage Top Bar */}
      <div style={{ padding:"6px 16px 10px", background:cl.navBar, backdropFilter:"blur(20px)", borderBottom:`0.5px solid ${cl.separator}`, flexShrink:0, zIndex:10 }}>
        <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between" }}>
          <div style={{ flex:1, display:"flex", justifyContent:"flex-start", alignItems:"center", gap:8 }}>
            <button onClick={goScenarios} style={{ background:"none", border:"none", color:cl.accent, fontSize:16, cursor:"pointer", fontFamily:sf, padding:0, display:"flex", alignItems:"center", gap:3 }}>
              <svg width="10" height="17" viewBox="0 0 10 17" fill="none"><path d="M9 1L1.5 8.5L9 16" stroke={cl.accent} strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/></svg>
            </button>
            {mode === "sim" && agentType && contextType && (
              <button onClick={()=>setShowCheat(true)} style={{ background:cl.orangeBg, border:"none", borderRadius:14, padding:"4px 10px", cursor:"pointer", fontFamily:sf, color:cl.orange, fontSize:11, fontWeight:700, display:"flex", alignItems:"center", gap:4, flexShrink:0 }}>
                📋 Script
              </button>
            )}
          </div>
          <div style={{ flex:"0 0 auto", textAlign:"center" }}>
            <div style={{ width:36, height:36, borderRadius:"50%", background:"linear-gradient(135deg,#5856d6,#af52de)", margin:"0 auto 3px", display:"flex", alignItems:"center", justifyContent:"center", fontSize:16, fontWeight:700, color:"#fff" }}>
              {situation.personaName[0]}
            </div>
            <div style={{ fontSize:13, fontWeight:600, color:cl.text }}>{situation.personaName}</div>
          </div>
          <div style={{ flex:1, display:"flex", alignItems:"center", justifyContent:"flex-end", gap:6 }}>
            <span style={{ fontSize:12, color:exchangeCount >= MAX-2 ? cl.yellow : cl.textDim, fontWeight:600, flexShrink:0 }}>{exchangeCount}/{MAX}</span>
            {simComplete ? (
              <button onClick={score} style={{ background:cl.accent, color:"#fff", border:"none", borderRadius:18, padding:"6px 14px", fontSize:12, fontWeight:700, cursor:"pointer", fontFamily:sf }}>Score</button>
            ) : (
              <button onClick={()=>setSimComplete(true)} style={{ background:"none", color:cl.textSoft, border:`1px solid ${cl.cardBorder}`, borderRadius:18, padding:"5px 12px", fontSize:11, cursor:"pointer", fontFamily:sf }}>End</button>
            )}
          </div>
        </div>
        {warnings.length > 0 && (
          <div style={{marginTop:8}}>
            {warnings.slice(-2).map((w,i)=>(
              <div key={i} style={{ animation:"warnSlide .25s ease", background:cl.redBg, borderRadius:8, padding:"5px 10px", fontSize:11, color:cl.red, marginTop:3, fontWeight:500 }}>⚠ {w.text}</div>
            ))}
          </div>
        )}
      </div>
      {/* Scenario briefing */}
      {messages.length === 0 && (
        <div style={{ margin:"10px 12px", padding:14, background:cl.card, borderRadius:16, border:`1px solid ${cl.cardBorder}`, animation:"fadeIn .4s ease", flexShrink:0 }}>
          <div style={{ fontSize:13, fontWeight:700, color:mode==="qualify"?cl.purple:cl.orange, marginBottom:8, display:"flex", alignItems:"center", gap:8 }}>
            {mode==="qualify"?"Qualification Round":"Your Scenario"}
            {lang !== "en" && <span style={{ background:cl.purpleBg, color:cl.purple, padding:"2px 8px", borderRadius:6, fontSize:10 }}>🗣 {lang === "fil" ? "Taglish" : "Spanish"}</span>}
          </div>
          <div style={{ fontSize:15.5, lineHeight:1.6, marginBottom:9 }}>{situation.openingContext}</div>
          {situation.history && (
            <div style={{ fontSize:13.5, color:cl.textSoft, lineHeight:1.6, marginBottom:9, paddingLeft:10, borderLeft:`2px solid ${mode==="qualify"?cl.purple:cl.orange}` }}>
              <strong style={{color:cl.text,fontWeight:600}}>Last between you:</strong> {situation.history}
            </div>
          )}
          <div style={{ fontSize:13, color:cl.textSoft, lineHeight:1.5 }}>
            <strong style={{color:cl.text}}>{situation.personaName}</strong>, {situation.personaAge}, {situation.personaTrait}
          </div>
          {mode === "qualify" && (
            <div style={{ marginTop:10, padding:"9px 12px", background:cl.purpleBg, borderRadius:10, fontSize:12.5, color:cl.purple, lineHeight:1.5 }}>
              This is a live, in person conversation. Type your replies for now so you can practice what you'd actually say out loud.
            </div>
          )}
          <div style={{marginTop:10}}>
            <button onClick={genOpeners} style={{ width:"100%", background:"rgba(10,132,255,0.08)", border:"none", borderRadius:openersOpen?"12px 12px 0 0":12, padding:"10px 12px", cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"space-between", fontFamily:sf, color:cl.accent, fontSize:13, fontWeight:600 }}>
              <span>💬 {openerUsed ? "Opener ideas" : "Need opener ideas? (1 use)"}</span>
              <span style={{fontSize:10,transition:"transform .2s",transform:openersOpen?"rotate(180deg)":"rotate(0)"}}>▾</span>
            </button>
            {openersOpen && (
              <div style={{ background:cl.card, borderRadius:"0 0 12px 12px", padding:"10px 12px", borderTop:`1px solid ${cl.separator}` }}>
                {openerLoading ? (
                  <div style={{display:"flex",alignItems:"center",gap:8,padding:"4px 0"}}>
                    <div style={{width:13,height:13,borderRadius:"50%",border:`2px solid ${cl.accent}40`,borderTopColor:cl.accent,animation:"spin .7s linear infinite",flexShrink:0}}/>
                    <div style={{fontSize:12,color:cl.textDim}}>Writing openers for {situation.personaName}...</div>
                  </div>
                ) : (
                  <>
                    <div style={{fontSize:11,color:cl.textDim,marginBottom:8,lineHeight:1.4}}>Tailored to {situation.personaName}. Use one as a starting point, then make it yours.</div>
                    {(openerIdeas || []).map((ex,i)=>(
                      <div key={i} style={{ background:cl.phoneBg, borderRadius:10, padding:"8px 10px", marginBottom:i<(openerIdeas||[]).length-1?5:0 }}>
                        <div style={{fontSize:13.5,color:cl.text,lineHeight:1.5}}>"{ex.text}"</div>
                        {ex.vibe && <div style={{fontSize:10,color:cl.textDim,fontStyle:"italic",marginTop:2}}>{ex.vibe}</div>}
                      </div>
                    ))}
                    <div style={{marginTop:8,fontSize:10,color:cl.yellow,lineHeight:1.4}}>
                      These are warm-ups. Script opener comes AFTER natural chat starts.
                    </div>
                  </>
                )}
              </div>
            )}
          </div>
        </div>
      )}
      {/* Messages Area */}
      <div style={{ flex:1, overflowY:"auto", padding:"8px 12px", display:"flex", flexDirection:"column", gap:3 }}>
        {messages.map((m,i) => {
          if (m.role === "system") {
            if (m.kind === "seen") {
              return (
                <div key={i} style={{ display:"flex", flexDirection:"column", alignItems:"flex-end", margin:"2px 6px 10px", animation:"fadeIn .3s ease" }}>
                  <span style={{ fontSize:12, color:cl.textSoft, fontWeight:700, letterSpacing:0.2 }}>Read</span>
                  <span style={{ fontSize:11, color:cl.textDim, marginTop:1 }}>Left on read, no reply</span>
                </div>
              );
            }
            return (
              <div key={i} style={{ textAlign:"center", margin:"12px 8px 8px", animation:"fadeIn .3s ease" }}>
                <span style={{ fontSize:11, color:cl.textDim, fontWeight:600, lineHeight:1.5 }}>⏳ {m.display || m.content}</span>
              </div>
            );
          }
          const isUser = m.role === "user";
          const prevSame = i > 0 && messages[i-1].role === m.role;
          return (
            <div key={i} style={{ display:"flex", justifyContent:isUser?"flex-end":"flex-start", animation:"fadeIn .2s ease", marginTop:prevSame?0:4 }}>
              <div style={{
                maxWidth:"75%", padding:"9px 14px",
                borderRadius: isUser
                  ? (prevSame ? "18px 6px 6px 18px" : "18px 18px 6px 18px")
                  : (prevSame ? "6px 18px 18px 18px" : "18px 18px 18px 6px"),
                background: isUser ? "#0A84FF" : cl.themBubble,
                color: isUser ? "#fff" : themBubbleText, fontSize:16, lineHeight:1.4, letterSpacing:-0.2,
              }}>{m.content}</div>
            </div>
          );
        })}
        {loading && (
          <div style={{display:"flex",animation:"fadeIn .2s ease",marginTop:4}}>
            <div style={{ padding:"12px 18px", borderRadius:"18px 18px 18px 6px", background:cl.themBubble }}>
              <div style={{display:"flex",gap:4,alignItems:"center"}}>
                {[0,1,2].map(i=>(<div key={i} style={{width:8,height:8,borderRadius:"50%",background:theme==="light"?"rgba(0,0,0,0.35)":"rgba(255,255,255,0.4)",animation:`pulse 1.2s ${i*0.15}s infinite`}}/>))}
              </div>
            </div>
          </div>
        )}
        <div ref={endRef}/>
      </div>
      {/* Prospect went quiet. Pre-link: warm human re-open, no cadence. Post-link: 24h then 48h nudges. */}
      {mode === "sim" && quietPending && !simComplete && (() => {
        const second = quietCount >= 2;
        const interval = second ? "48h" : "24h";
        if (!linkSent) {
          return (
            <div style={{ padding:"0 12px 6px", flexShrink:0, animation:"fadeIn .3s ease" }}>
              <div style={{ background:cl.card, border:`1px solid ${cl.cardBorder}`, borderRadius:14, padding:"12px 14px" }}>
                <div style={{ fontSize:12.5, color:cl.textSoft, lineHeight:1.5, marginBottom:10 }}>
                  {situation.personaName} went quiet, but you never actually asked for anything yet, so this isn't a follow-up and there's no 24h rule here. A few hours is nothing. Re-open like a friend, lighter than before, and circle back to something they shared.
                </div>
                <button onClick={()=>{ setMessages(p=>[...p,{ role:"system", kind:"gap", display:"A couple days later." }]); setQuietPending(false); setPendingFollowUp(true); setTimeout(()=>inputRef.current?.focus(),150); }}
                  style={{ width:"100%", padding:12, borderRadius:14, border:"none", background:cl.accent, color:"#fff", fontSize:14, fontWeight:700, cursor:"pointer", fontFamily:sf, marginBottom:8 }}>
                  Give it a beat, then re-open warm
                </button>
                <button onClick={score}
                  style={{ width:"100%", padding:10, borderRadius:14, border:`1px solid ${cl.cardBorder}`, background:"none", color:cl.textDim, fontSize:13, fontWeight:600, cursor:"pointer", fontFamily:sf }}>
                  Move on to the next
                </button>
              </div>
            </div>
          );
        }
        return (
          <div style={{ padding:"0 12px 6px", flexShrink:0, animation:"fadeIn .3s ease" }}>
            <div style={{ background:cl.card, border:`1px solid ${cl.cardBorder}`, borderRadius:14, padding:"12px 14px" }}>
              <div style={{ fontSize:12.5, color:cl.textSoft, lineHeight:1.5, marginBottom:10 }}>
                {situation.personaName} hasn't replied to the link. Two nudges total, {second ? "this is your second and last one, then you leave the door open." : "and the first comes at 24 hours, not now. Give it the day, then a light nudge."}
              </div>
              <button onClick={()=>{ setMessages(p=>[...p,{ role:"system", kind:"gap", display: second ? "48 hours later." : "24 hours later." }]); setQuietPending(false); setPendingFollowUp(true); setTimeout(()=>inputRef.current?.focus(),150); }}
                style={{ width:"100%", padding:12, borderRadius:14, border:"none", background:cl.accent, color:"#fff", fontSize:14, fontWeight:700, cursor:"pointer", fontFamily:sf, marginBottom:8 }}>
                Wait {interval}, then send your {second ? "second" : "first"} nudge
              </button>
              <button onClick={()=>{ setQuietPending(false); setPendingFollowUp(true); setTimeout(()=>inputRef.current?.focus(),150); }}
                style={{ width:"100%", padding:10, borderRadius:14, border:`1px solid ${cl.cardBorder}`, background:"none", color:cl.textSoft, fontSize:13, fontWeight:700, cursor:"pointer", fontFamily:sf, marginBottom:8 }}>
                Text again now
              </button>
              <button onClick={score}
                style={{ width:"100%", padding:10, borderRadius:14, border:`1px solid ${cl.cardBorder}`, background:"none", color:cl.textDim, fontSize:13, fontWeight:600, cursor:"pointer", fontFamily:sf }}>
                Move on to the next
              </button>
            </div>
          </div>
        );
      })()}
      {mode === "sim" && linkSent && !simComplete && !quietPending && !pendingFollowUp && (() => {
        const cc = getCloseCoach(linkType);
        if (closing) {
          return (
            <div style={{ padding:"0 12px 6px", flexShrink:0, animation:"fadeIn .3s ease" }}>
              <div style={{ display:"flex", alignItems:"center", gap:10, background:cl.greenBg, border:`1px solid ${cl.green}40`, borderRadius:14, padding:"8px 10px 8px 13px" }}>
                <div style={{flex:1,fontSize:12.5,color:cl.textSoft,lineHeight:1.4}}>Close it clean, keep it short, then tap when you're done.</div>
                <button onClick={score} style={{ flexShrink:0, padding:"9px 13px", borderRadius:16, border:"none", background:cl.green, color:"#fff", fontSize:13, fontWeight:700, cursor:"pointer", fontFamily:sf }}>
                  Coach me now
                </button>
              </div>
            </div>
          );
        }
        return (
          <div style={{ padding:"0 12px 6px", flexShrink:0, animation:"fadeIn .3s ease" }}>
            <div style={{ background:cl.greenBg, border:`1px solid ${cl.green}40`, borderRadius:14, padding:"12px 14px" }}>
              <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:6 }}>
                <span style={{fontSize:16}}>🎉</span>
                <div style={{fontSize:14,fontWeight:800,color:cl.green}}>Link sent. That's the win.</div>
              </div>
              <div style={{fontSize:13,color:cl.textSoft,lineHeight:1.55,marginBottom:6}}>Now close it clean, don't keep selling. {cc.whatIs} Lock the next step and add the referral:</div>
              <div style={{fontSize:13,color:cl.text,lineHeight:1.55,background:cl.phoneBg,borderRadius:10,padding:"8px 11px",marginBottom:10,fontStyle:"italic"}}>"{cc.close}"</div>
              <button onClick={()=>setClosing(true)} style={{ width:"100%", padding:12, borderRadius:18, border:"none", background:cl.green, color:"#fff", fontSize:14, fontWeight:700, cursor:"pointer", fontFamily:sf, marginBottom:8 }}>
                Keep going, close it clean
              </button>
              <button onClick={score} style={{ width:"100%", padding:11, borderRadius:18, border:`1px solid ${cl.green}40`, background:"none", color:cl.green, fontSize:13.5, fontWeight:700, cursor:"pointer", fontFamily:sf }}>
                Coach me now
              </button>
            </div>
          </div>
        );
      })()}
      {/* Ask Mav AI lifeline (2 per conversation) */}
      {!simComplete && !quietPending && !(mode === "sim" && linkSent) && (
        hintLoading ? (
          <div style={{ padding:"0 12px 6px", flexShrink:0, animation:"fadeIn .3s ease" }}>
            <div style={{ background:theme==="light"?"rgba(48,209,88,0.1)":"rgba(48,209,88,0.12)", borderRadius:14, padding:"10px 14px", display:"flex", alignItems:"center", gap:8 }}>
              <div style={{width:13,height:13,borderRadius:"50%",border:`2px solid ${cl.green}40`,borderTopColor:cl.green,animation:"spin .7s linear infinite",flexShrink:0}}/>
              <div style={{fontSize:13,color:cl.textDim,lineHeight:1.5}}>Mav AI is reading the conversation...</div>
            </div>
          </div>
        ) : hint ? (
          <div style={{ padding:"0 12px 6px", flexShrink:0, animation:"fadeIn .3s ease" }}>
            <div style={{ background:theme==="light"?"rgba(48,209,88,0.1)":"rgba(48,209,88,0.12)", borderRadius:14, padding:"10px 14px", display:"flex", alignItems:"flex-start", gap:8 }}>
              <span style={{fontSize:13,flexShrink:0,marginTop:1}}>⚡</span>
              <div style={{flex:1}}>
                <div style={{fontSize:11,fontWeight:700,color:cl.green,marginBottom:3}}>Mav AI · {hintsUsed}/2 used{hintsUsed>=2?" (last one)":""}</div>
                <div style={{fontSize:13,color:cl.textSoft,lineHeight:1.5}}>{hint}</div>
              </div>
              <button onClick={()=>setHint(null)} style={{background:"none",border:"none",color:cl.textDim,fontSize:16,cursor:"pointer",padding:0,lineHeight:1,flexShrink:0}}>×</button>
            </div>
          </div>
        ) : hintsUsed < 2 ? (
          <div style={{ padding:"0 12px 6px", flexShrink:0 }}>
            <button onClick={askMav}
              style={{ width:"100%", background:theme==="light"?"rgba(48,209,88,0.1)":"rgba(48,209,88,0.12)", border:`1px solid ${cl.green}30`, borderRadius:14, padding:"9px 14px", cursor:"pointer", fontFamily:sf, color:cl.green, fontSize:13, fontWeight:700, display:"flex", alignItems:"center", justifyContent:"center", gap:7 }}>
              ⚡ Ask Mav AI · {2 - hintsUsed} left
            </button>
          </div>
        ) : (
          <div style={{ padding:"0 12px 6px", flexShrink:0, textAlign:"center" }}>
            <span style={{ fontSize:11, color:cl.textDim }}>No asks left. Back yourself and make the call.</span>
          </div>
        )
      )}
      {/* Input Bar */}
      <div style={{ padding:"8px 12px 4px", flexShrink:0 }}>
        {simComplete ? (
          <button onClick={score} style={{ width:"100%", padding:14, borderRadius:24, border:"none", background:cl.accent, color:"#fff", fontSize:16, fontWeight:700, cursor:"pointer", fontFamily:sf }}>
            {mode==="qualify"?"Get Qualification Score":"Get My Score & Coaching"}
          </button>
        ) : (quietPending || (mode === "sim" && linkSent && !closing && !pendingFollowUp)) ? null : (
          /* ── TEXT MODE INPUT ── */
          <div style={{ display:"flex", gap:8, alignItems:"flex-end" }}>
            <div style={{ flex:1, display:"flex", alignItems:"center", background:cl.inputBg, borderRadius:22, border:`1px solid ${cl.cardBorder}`, padding:"0 4px 0 16px" }}>
              <input ref={inputRef} type="text" value={input} onChange={e=>setInput(e.target.value)} onKeyDown={e=>e.key==="Enter"&&send()} placeholder={mode==="qualify"?"What do you say?":"iMessage"} disabled={loading}
                style={{ flex:1, padding:"11px 0", background:"transparent", border:"none", color:cl.text, fontSize:16, fontFamily:sf, outline:"none", letterSpacing:-0.2 }}/>
              <button onClick={send} disabled={!input.trim()||loading}
                style={{ width:30, height:30, borderRadius:"50%", border:"none", background:input.trim()?cl.accent:"transparent", color:"#fff", fontSize:15, cursor:input.trim()?"pointer":"default", display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0, margin:3, transition:"background 0.15s" }}>
                {input.trim() && <svg width="14" height="14" viewBox="0 0 14 14" fill="none"><path d="M7 12V2M7 2L2.5 6.5M7 2L11.5 6.5" stroke="#fff" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>}
              </button>
            </div>
          </div>
        )}
      </div>
      {showCheat && mode === "sim" && agentType && contextType && (()=>{
        const at = AGENT_TYPES[agentType];
        const cs = (contextType==="warm") ? at.scriptWarm : (contextType==="social") ? (at.scriptSocial||at.scriptCold) : at.scriptCold;
        const steps = [
          { n:"1", title:"Warm up the conversation", note:"Be a real person first. React to what they said. The ask only lands once the convo is already flowing." },
          { n:"2", title:"The no big deal ask", line:cs.opener },
          { n:"3", title:"Transition, then send the link", line:cs.ifYes },
          { n:"3", title:"Drop the link", line:cs.sendLink },
          { n:"4", title:"Thank you and pass along", line:"appreciate you taking a look 🙂 if this feels useful to anyone in your world, feel free to share it. either way, good catching up." },
          { n:"?", title:"If they ask what it is", line:"it actually makes more sense once you see it than me trying to explain over text. take a quick look and lmk what you think :)" },
        ];
        return (
          <div onClick={()=>setShowCheat(false)} style={{ position:"absolute", inset:0, zIndex:80, background:"rgba(0,0,0,0.55)", display:"flex", alignItems:"flex-end", animation:"fadeIn .2s ease" }}>
            <div onClick={e=>e.stopPropagation()} style={{ width:"100%", maxHeight:"84%", overflowY:"auto", background:cl.bg, borderRadius:"20px 20px 0 0", borderTop:`1px solid ${cl.cardBorder}`, padding:"16px 18px 24px", boxShadow:cl.shellShadow }}>
              <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:4 }}>
                <div style={{ fontSize:17, fontWeight:800, color:cl.heading, letterSpacing:-0.3 }}>The 4-step script</div>
                <button onClick={()=>setShowCheat(false)} style={{ background:"none", border:"none", color:cl.textDim, fontSize:24, cursor:"pointer", lineHeight:1, padding:0, fontFamily:sf }}>×</button>
              </div>
              <div style={{ fontSize:12, color:cl.textDim, marginBottom:14, lineHeight:1.5 }}>Quick reference. The link explains, you don't. Earn the click, then stop selling.</div>
              {steps.map((s,i)=>(
                <div key={i} style={{ marginBottom:12 }}>
                  <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:5 }}>
                    <div style={{ width:20, height:20, borderRadius:6, background:cl.orangeBg, color:cl.orange, fontSize:11, fontWeight:800, display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 }}>{s.n}</div>
                    <div style={{ fontSize:13.5, fontWeight:700, color:cl.text }}>{s.title}</div>
                  </div>
                  {s.note ? (
                    <div style={{ fontSize:13, color:cl.textSoft, lineHeight:1.55, paddingLeft:28 }}>{s.note}</div>
                  ) : (
                    <div style={{ marginLeft:28, background:cl.card, border:`1px solid ${cl.cardBorder}`, borderRadius:12, padding:"10px 13px", fontSize:13.5, color:cl.text, lineHeight:1.55, whiteSpace:"pre-wrap" }}>{s.line}</div>
                  )}
                </div>
              ))}
              <div style={{ fontSize:11, color:cl.textDim, lineHeight:1.45, marginTop:6 }}>After: two nudges, 24h then 48h, then leave it.</div>
            </div>
          </div>
        );
      })()}
    </PhoneShell>
  );

  // ══ SIGNAL SPOTTER ══
  if (screen === "spotter" && spotterOrder.length > 0) {
    const p = SPOTTER_PROFILES[spotterOrder[spotterIndex]];
    return (
      <PhoneShell cl={cl} theme={theme}>
        <div style={{ flex:1, padding:"16px 20px", overflowY:"auto" }}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
            <BackBtn onClick={goHome} label="Home" cl={cl} />
            <span style={{fontSize:12,color:cl.textDim}}>{spotterIndex+1}/{spotterOrder.length}</span>
          </div>
          <div style={{ display:"inline-block", padding:"5px 12px", borderRadius:8, background:cl.orangeBg, color:cl.orange, fontSize:12, fontWeight:600, marginTop:16, marginBottom:8 }}>
            Signal Spotter
          </div>
          <h2 style={{ fontSize:24, fontWeight:800, letterSpacing:-0.5, marginBottom:18, color:cl.heading }}>Read the Prospect</h2>
          <div style={{ background:cl.card, borderRadius:20, padding:18, border:`1px solid ${cl.cardBorder}`, marginBottom:14 }}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:14}}>
              <div>
                <div style={{fontSize:20,fontWeight:800,letterSpacing:-0.5}}>{p.name}</div>
                <div style={{fontSize:14,color:cl.textSoft,marginTop:2}}>{p.age} · {p.job}</div>
              </div>
              <div style={{fontSize:12,color:cl.textDim,textAlign:"right",maxWidth:120}}>{p.family}</div>
            </div>
            <div style={{fontSize:12,fontWeight:600,color:cl.textDim,marginBottom:8}}>Recent posts</div>
            {p.recentPosts.map((post,i)=>(
              <div key={i} style={{background:cl.phoneBg,borderRadius:12,padding:"9px 12px",marginBottom:5,fontSize:14,color:cl.textSoft,lineHeight:1.5}}>"{post}"</div>
            ))}
            <div style={{marginTop:12,fontSize:13,color:cl.textDim,lineHeight:1.5}}><strong style={{color:cl.textSoft}}>Context:</strong> {p.lifeContext}</div>
          </div>
          {!spotterRevealed ? (
            <>
              <div style={{fontSize:13,fontWeight:600,color:cl.textDim,marginBottom:10}}>Best link for this person?</div>
              {[
                {key:"efa",label:"EFA (Financial clarity)",col:cl.orange},
                {key:"recruit_unlicensed",label:"Recruit (Unlicensed)",col:cl.green},
                {key:"recruit_licensed",label:"Recruit (Licensed)",col:cl.purple},
                {key:"not_prospect",label:"Not a Prospect",col:cl.red},
              ].map(opt=>(
                <button key={opt.key} onClick={()=>spotterSubmit(opt.key)}
                  style={{ width:"100%", display:"flex", alignItems:"center", gap:12, background:cl.card, border:`1px solid ${cl.cardBorder}`, borderRadius:14, padding:"14px 16px", marginBottom:6, cursor:"pointer", fontFamily:sf, color:cl.text }}
                  onMouseDown={e=>e.currentTarget.style.transform="scale(0.98)"} onMouseUp={e=>e.currentTarget.style.transform="scale(1)"} onMouseLeave={e=>e.currentTarget.style.transform="scale(1)"}
                >
                  <div style={{width:10,height:10,borderRadius:"50%",background:opt.col,flexShrink:0}}/>
                  <div style={{fontSize:14,fontWeight:500}}>{opt.label}</div>
                </button>
              ))}
            </>
          ) : (
            <div>
              <div style={{background:spotterAnswer===p.answer?cl.greenBg:cl.redBg,borderRadius:14,padding:16,marginBottom:12,textAlign:"center"}}>
                <div style={{fontSize:17,fontWeight:800,color:spotterAnswer===p.answer?cl.green:cl.red}}>{spotterAnswer===p.answer?"Correct!":"Not quite."}</div>
                <div style={{fontSize:14,color:cl.textSoft,marginTop:4}}>Answer: <strong style={{color:cl.text}}>{p.answer==="not_prospect"?"Not a Prospect":(LINK_TYPES[p.answer]?.label||p.answer)}</strong></div>
              </div>
              <div style={{background:cl.card,borderRadius:14,padding:16,marginBottom:14,border:`1px solid ${cl.cardBorder}`}}>
                <div style={{fontSize:14,color:cl.text,lineHeight:1.7}}>{p.reasoning}</div>
              </div>
              <button onClick={spotterNext}
                style={{width:"100%",padding:15,borderRadius:24,border:"none",background:cl.accent,color:"#fff",fontSize:16,fontWeight:700,cursor:"pointer",fontFamily:sf}}>
                {spotterIndex+1>=spotterOrder.length?"See Results":"Next Profile →"}
              </button>
            </div>
          )}
        </div>
      </PhoneShell>
    );
  }

  // ══ SPOTTER DONE ══
  if (screen === "spotterDone") return (
    <PhoneShell cl={cl} theme={theme}>
      <div style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:"32px 24px",textAlign:"center"}}>
        <div style={{fontSize:56,marginBottom:20}}>{spotterStats.correct >= spotterStats.total * 0.8 ? "🔥" : spotterStats.correct >= spotterStats.total * 0.6 ? "👍" : "📚"}</div>
        <h2 style={{fontSize:26,fontWeight:800,marginBottom:8,letterSpacing:-0.5,color:cl.heading}}>Signal Spotter</h2>
        <div style={{fontSize:48,fontWeight:800,color:spotterStats.correct>=spotterStats.total*0.8?cl.green:spotterStats.correct>=spotterStats.total*0.6?cl.yellow:cl.red,marginBottom:8}}>
          {spotterStats.correct}/{spotterStats.total}
        </div>
        <div style={{fontSize:15,color:cl.textSoft,lineHeight:1.6,marginBottom:36,maxWidth:320}}>
          {spotterStats.correct >= spotterStats.total * 0.8 ? "Sharp eye. You know which door to open with each person." : spotterStats.correct >= spotterStats.total * 0.6 ? "Getting there. Almost everyone is at least an EFA prospect. Recruit signals upgrade the play." : "Study the signals. Recruit signals = lead with recruit. Everyone else = EFA."}
        </div>
        <div style={{display:"flex",gap:10}}>
          <button onClick={startSpotter} style={{padding:"14px 28px",borderRadius:24,border:"none",background:cl.accent,color:"#fff",fontSize:15,fontWeight:700,cursor:"pointer",fontFamily:sf}}>Play Again</button>
          <button onClick={goHome} style={{padding:"14px 22px",borderRadius:24,border:`1px solid ${cl.cardBorder}`,background:"none",color:cl.textSoft,fontSize:15,fontWeight:600,cursor:"pointer",fontFamily:sf}}>Home</button>
        </div>
      </div>
    </PhoneShell>
  );

  // ══ SCORE ══
  if (screen === "score") return (
    <PhoneShell cl={cl} theme={theme}>
      <style>{`@keyframes spin{to{transform:rotate(360deg)}} .bar-fill{transition:width .8s cubic-bezier(.22,1,.36,1)}`}</style>
      <div style={{flex:1,padding:"16px 18px",overflowY:"auto"}}>
        {scoringLoading ? (
          <div style={{display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",height:"100%",gap:16}}>
            <div style={{width:40,height:40,borderRadius:"50%",border:`3px solid ${cl.cardBorder}`,borderTopColor:cl.accent,animation:"spin .7s linear infinite"}}/>
            <div style={{fontSize:15,color:cl.textSoft}}>Analyzing your conversation...</div>
          </div>
        ) : scoring?.error ? (
          <div style={{textAlign:"center",paddingTop:100}}>
            <div style={{fontSize:15,color:cl.red,marginBottom:20}}>Scoring failed.</div>
            <button onClick={goScenarios} style={{padding:"14px 28px",borderRadius:24,border:"none",background:cl.accent,color:"#fff",fontSize:15,fontWeight:700,cursor:"pointer",fontFamily:sf}}>Try Again</button>
          </div>
        ) : scoring && (() => {
          const toggle = (k) => setOpenSections(s => ({ ...s, [k]: !s[k] }));
          const Drop = ({ k, title, count, accent, children }) => {
            const o = !!openSections[k];
            const ac = accent || cl.accent;
            return (
            <div style={{ background: o ? `${ac}0d` : cl.card, borderRadius:14, marginBottom:8, border:`1px solid ${o ? ac : cl.cardBorder}`, overflow:"hidden", transition:"background .2s, border-color .2s" }}>
              <button onClick={()=>toggle(k)} style={{ width:"100%", background:"none", border:"none", cursor:"pointer", padding:"14px 16px", display:"flex", alignItems:"center", justifyContent:"space-between", fontFamily:sf }}>
                <span style={{ display:"flex", alignItems:"center", gap:8 }}>
                  <span style={{ fontSize:14, fontWeight:700, color: accent||cl.text }}>{title}</span>
                  {count!=null && <span style={{ fontSize:12, color:cl.textDim, background:cl.bg, borderRadius:10, padding:"1px 8px" }}>{count}</span>}
                </span>
                <Chevron open={o} color={ac} />
              </button>
              {o && <div style={{ padding:"0 16px 14px" }}>{children}</div>}
            </div>
          );};
          return (
          <div>
            <div style={{textAlign:"center",marginBottom:20}}>
              <div style={{
                display:"inline-flex",alignItems:"center",justifyContent:"center",width:80,height:80,borderRadius:"50%",
                fontSize:34,fontWeight:800,
                background:scoring.passed?cl.greenBg:cl.orangeBg,color:scoring.passed?cl.green:cl.orange,
                border:`2px solid ${scoring.passed?cl.green:cl.orange}40`,marginBottom:10
              }}>{scoring.grade}</div>
              <div style={{fontSize:22,fontWeight:800,color:scoring.passed?cl.green:cl.orange,marginBottom:4,letterSpacing:-0.5}}>{scoring.passed?"Passed":"Needs improvement"}</div>
              <div style={{fontSize:14,color:cl.textSoft}}>{scoring.total_score}/50 · {situation.personaName}</div>
            </div>

            {/* Coaching tip stays front and center */}
            {scoring.coaching_tip&&(
              <div style={{background:cl.orangeBg,borderRadius:14,padding:16,marginBottom:14}}>
                <div style={{fontSize:13,fontWeight:600,color:cl.orange,marginBottom:6}}>The one thing to fix</div>
                <div style={{fontSize:16,lineHeight:1.5,fontWeight:500,color:cl.text}}>{scoring.coaching_tip}</div>
              </div>
            )}

            {/* Door fit: did they prospect the right path */}
            {mode==="sim"&&scoring.door_fit&&(
              <div style={{background:scoring.door_fit.matched?cl.greenBg:cl.redBg,borderRadius:14,padding:16,marginBottom:14}}>
                <div style={{fontSize:13,fontWeight:600,color:scoring.door_fit.matched?cl.green:cl.red,marginBottom:6}}>
                  {scoring.door_fit.matched?"Right door":"Wrong door"}
                </div>
                <div style={{fontSize:15,lineHeight:1.5,fontWeight:600,color:cl.text,marginBottom:scoring.door_fit.coaching?6:0}}>
                  You ran {scoring.door_fit.chosen}.{scoring.door_fit.matched?" Good read on the signals." : scoring.door_fit.better?` This was a better fit for ${scoring.door_fit.better}.`:""}
                </div>
                {scoring.door_fit.coaching&&<div style={{fontSize:14,lineHeight:1.6,color:cl.textSoft}}>{scoring.door_fit.coaching}</div>}
              </div>
            )}

            {/* Qualify verdict stays visible */}
            {mode==="qualify"&&scoring.verdict&&(
              <div style={{background:scoring.verdict==="QUALIFIED"?cl.greenBg:scoring.verdict==="NOT QUALIFIED"?cl.redBg:cl.yellowBg,borderRadius:14,padding:14,marginBottom:14,textAlign:"center"}}>
                <div style={{fontSize:15,fontWeight:800,color:scoring.verdict==="QUALIFIED"?cl.green:scoring.verdict==="NOT QUALIFIED"?cl.red:cl.yellow}}>{scoring.verdict}</div>
              </div>
            )}

            <div style={{fontSize:12,color:cl.textDim,marginBottom:10}}>Tap to see the details</div>

            {/* Score breakdown dropdown */}
            <Drop k="breakdown" title="Score breakdown" count={`${scoring.total_score}/50`}>
              {scoring.scores&&Object.entries(scoring.scores).map(([k,v],i,a)=>(
                <div key={k} style={{marginBottom:i<a.length-1?14:0,marginTop:i===0?4:0}}>
                  <div style={{display:"flex",justifyContent:"space-between",fontSize:13,marginBottom:5}}>
                    <span style={{color:cl.textSoft}}>{SCORE_LABELS[k] || k.replace(/_/g," ")}</span>
                    <span style={{fontWeight:700,color:v.score>=7?cl.green:v.score>=5?cl.yellow:cl.red}}>{v.score}/10</span>
                  </div>
                  <div style={{height:4,borderRadius:2,background:cl.bg,overflow:"hidden"}}>
                    <div className="bar-fill" style={{height:"100%",width:`${v.score*10}%`,borderRadius:2,background:v.score>=7?cl.green:v.score>=5?cl.yellow:cl.red}}/>
                  </div>
                  <div style={{fontSize:12,color:cl.textDim,marginTop:4,lineHeight:1.4}}>{v.detail}</div>
                </div>
              ))}
            </Drop>

            {/* What you did right */}
            {scoring.green_flags?.length>0&&(
              <Drop k="green" title="What you did right" count={scoring.green_flags.length} accent={cl.green}>
                {scoring.green_flags.map((f,i)=><div key={i} style={{fontSize:14,lineHeight:1.6,padding:"5px 0",color:cl.text}}>✓ {f}</div>)}
              </Drop>
            )}

            {/* What to fix */}
            {scoring.red_flags?.length>0&&(
              <Drop k="red" title="What to fix" count={scoring.red_flags.length} accent={cl.red}>
                {scoring.red_flags.map((f,i)=><div key={i} style={{fontSize:14,lineHeight:1.6,padding:"5px 0",color:cl.text}}>✕ {f}</div>)}
              </Drop>
            )}

            {/* Qualify signals */}
            {mode==="qualify"&&scoring.signals_found?.length>0&&(
              <Drop k="sigFound" title="Signals you caught" count={scoring.signals_found.length} accent={cl.green}>
                {scoring.signals_found.map((s,i)=><div key={i} style={{fontSize:14,lineHeight:1.6,padding:"5px 0",color:cl.text}}>✓ {s}</div>)}
              </Drop>
            )}
            {mode==="qualify"&&scoring.signals_missed?.length>0&&(
              <Drop k="sigMissed" title="Signals you missed" count={scoring.signals_missed.length} accent={cl.yellow}>
                {scoring.signals_missed.map((s,i)=><div key={i} style={{fontSize:14,lineHeight:1.6,padding:"5px 0",color:cl.text}}>○ {s}</div>)}
              </Drop>
            )}

            {mode==="sim"&&(
              <button onClick={coachWithMav} style={{width:"100%",padding:14,borderRadius:24,border:"none",background:cl.green,color:"#fff",fontSize:15,fontWeight:700,cursor:"pointer",fontFamily:sf,marginTop:14,display:"flex",alignItems:"center",justifyContent:"center",gap:8}}>
                ⚡ Continue with Mav AI
              </button>
            )}
            <div style={{display:"flex",gap:10,marginTop:mode==="sim"?10:14,marginBottom:12}}>
              <button onClick={goScenarios} style={{flex:1,padding:15,borderRadius:24,border:"none",background:cl.accent,color:"#fff",fontSize:15,fontWeight:700,cursor:"pointer",fontFamily:sf}}>Play Again</button>
              <button onClick={goHome} style={{padding:"15px 20px",borderRadius:24,border:`1px solid ${cl.cardBorder}`,background:"none",color:cl.textSoft,fontSize:15,fontWeight:600,cursor:"pointer",fontFamily:sf}}>Home</button>
            </div>
          </div>
          );
        })()}
      </div>
    </PhoneShell>
  );

  return null;
}
